-- Schema for Domain: quality | Business: Agriculture | Version: v1_ecm
-- Generated on: 2026-05-01 16:23:39

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`quality` COMMENT 'SSOT for all quality assurance and food safety compliance data across production and supply chain. Manages COA records, HACCP critical control point logs, MRL testing results, GAP/GMP audit findings, GFSI certification status (SQF, BRC, IFS), FSMA compliance records, inspection programs, testing protocols, non-conformance tracking, and corrective actions. Integrates with SAP S/4HANA QM module and supports USDA, FDA, and FSIS regulatory reporting. Maintains certification readiness for GLOBALG.A.P. audits.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`inspection` (
    `inspection_id` BIGINT COMMENT 'Unique system-generated identifier for each inspection event. Primary key for the quality inspection master record.',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: GAP and food safety inspections in agriculture are frequently conducted at the crew level — inspecting a specific harvest or packing crews GMP/food safety practices. Linking inspection to the crew be',
    `employee_id` BIGINT COMMENT 'Reference to the individual (internal auditor, third-party inspector, or regulatory officer) who conducted the inspection.',
    `facility_id` BIGINT COMMENT 'Reference to the facility, storage location, processing plant, or field site where the inspection was conducted.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: USDA Organic and GlobalG.A.P. certification inspections are scoped to the entire farm operation (farm_unit), not individual fields or facilities. This link enables farm-level inspection history requir',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: GAP field inspections and FSMA Produce Safety Rule inspections are conducted at the field level. Linking inspection to field enables traceability of which fields passed/failed GAP audits — a core requ',
    `food_safety_plan_id` BIGINT COMMENT 'Foreign key linking to compliance.food_safety_plan. Business justification: FSMA requires quality inspections to verify conformance to the facilitys active food safety plan. Inspectors review the food safety plan during GAP/GFSI audits; linking enables compliance officers to',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: USDA AMS grade inspections and GAP inspections evaluate compliance against specific grading standards. The inspection stores grade as denormalized text. Linking to grading_standard enables grade certi',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: Inspections in food safety contexts are frequently conducted against a specific HACCP plan — verifying CCP monitoring, critical limits, and corrective action procedures. inspection has haccp_ccp_compl',
    `inspection_record_id` BIGINT COMMENT 'Foreign key linking to compliance.inspection_record. Business justification: Quality inspections (GAP, GFSI, HACCP) are cross-referenced with official regulatory inspection records filed with agencies. Food safety auditors and compliance officers must reconcile quality inspect',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Regulatory inspections verify permit compliance (CAFO permits, water withdrawal permits, pesticide applicator permits). Linking quality inspection records to the governing permit enables permit compli',
    `regulatory_agency_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_agency. Business justification: quality.inspection has a plain-text regulatory_body column. Normalizing to compliance.regulatory_agency enables agency-level inspection reporting, enforcement tracking, and contact management. Agricul',
    `spray_window_id` BIGINT COMMENT 'Foreign key linking to weather.spray_window. Business justification: GAP and pesticide compliance inspections verify that spray applications occurred within compliant spray windows (PHI, REI, EPA drift constraints). Linking inspection to the spray_window record provide',
    `actual_date` DATE COMMENT 'The calendar date on which the inspection was actually performed. May differ from scheduled_date due to rescheduling or operational delays.',
    `certification_eligible` BOOLEAN COMMENT 'Indicates whether the inspection outcome qualifies the facility or operation for certification or recertification under the applicable standard. Derived from score thresholds and major non-conformance counts.',
    `certification_standard` STRING COMMENT 'The food safety or agricultural certification standard against which this inspection was conducted (e.g., GLOBALG.A.P., SQF Level 2, BRC Global Standard). Drives checklist selection and certification eligibility assessment.. Valid values are `GLOBALG.A.P.|SQF|BRC|IFS|ISO_22000|FSMA|NOP|HACCP|none`',
    `corrective_action_due_date` DATE COMMENT 'Deadline by which all mandated corrective actions from this inspection must be completed and verified. Drives compliance follow-up scheduling and escalation workflows.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether one or more corrective actions have been mandated as a result of this inspection. Triggers downstream corrective action tracking workflow.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the inspection record was first created in the system. Supports audit trail requirements and data lineage tracking.',
    `end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the inspection activity was concluded, enabling duration calculation and scheduling analytics.',
    `gap_module_ag_water_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Agricultural Water section of a GAP compliance assessment. Evaluates water source testing, microbial standards, irrigation method risk, and water quality records per FSMA and USDA GAP requirements.',
    `gap_module_field_sanitation_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Field Sanitation and Hygiene section of a GAP compliance assessment. Evaluates toilet facilities, handwashing stations, field equipment sanitation, and harvest container cleanliness.',
    `gap_module_soil_amendments_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Soil Amendments section of a GAP compliance assessment. Evaluates manure application intervals, compost treatment standards, and biological soil amendment risk management.',
    `gap_module_traceability_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Traceability and Recordkeeping section of a GAP compliance assessment. Evaluates lot identification, harvest records, chain-of-custody documentation, and recall readiness.',
    `gap_module_worker_health_score` DECIMAL(18,2) COMMENT 'Module-level compliance score for the Worker Health, Hygiene, and Training section of a GAP compliance assessment. Evaluates handwashing facilities, illness policies, training records, and personal hygiene practices per FSMA Produce Safety Rule requirements.',
    `gis_coordinates` STRING COMMENT 'GPS latitude and longitude coordinates of the inspection site in decimal degrees format, enabling geospatial analysis and field mapping via Esri ArcGIS integration.. Valid values are `^-?([1-8]?[0-9](.[0-9]+)?|90(.0+)?),s*-?(1[0-7][0-9](.[0-9]+)?|[1-9]?[0-9](.[0-9]+)?|180(.0+)?)$`',
    `inspection_number` STRING COMMENT 'Externally-known business identifier for the inspection event, used in regulatory submissions, audit trails, and cross-system references (e.g., SAP QM inspection lot number).. Valid values are `^INS-[0-9]{4}-[0-9]{6}$`',
    `inspection_scope` STRING COMMENT 'Operational area or stage of the agricultural supply chain covered by this inspection event (e.g., field operations, post-harvest handling, cold storage, processing facility, inbound receiving). [ENUM-REF-CANDIDATE: field|post_harvest|storage|processing|supply_chain|receiving|pre_operational — 7 candidates stripped; promote to reference product]',
    `inspection_status` STRING COMMENT 'Current lifecycle state of the inspection record, tracking progression from scheduling through completion and review.. Valid values are `scheduled|in_progress|completed|cancelled|pending_review`',
    `inspection_type` STRING COMMENT 'Classification of the inspection by its regulatory or operational framework. Determines the checklist, scoring methodology, and applicable standards applied during the inspection. [ENUM-REF-CANDIDATE: GAP|GMP|HACCP|FSMA|GLOBALG.A.P.|pre_operational|receiving|internal_audit|FSIS|APHIS — promote to reference product]. Valid values are `GAP|GMP|HACCP|FSMA|GLOBALG.A.P.|pre_operational|receiving|internal_audit`',
    `inspector_credential` STRING COMMENT 'Certification or credential held by the inspector (e.g., PCQI - Preventive Controls Qualified Individual, Lead Auditor ISO 22000, GLOBALG.A.P. approved CB auditor). Validates inspector qualification for the inspection type.',
    `inspector_organization` STRING COMMENT 'Name of the organization or agency the inspector represents (e.g., USDA AMS, FDA district office, third-party certification body such as NSF, SGS, or Bureau Veritas). Distinguishes internal from external inspections.',
    `location_description` STRING COMMENT 'Free-text description of the specific location inspected, such as field block identifier, warehouse bay, processing line number, or cold storage unit. Complements the structured facility_id reference.',
    `major_nonconformance_count` STRING COMMENT 'Number of major non-conformances (critical findings) identified during the inspection. Major non-conformances typically result in automatic certification failure or mandatory corrective action before re-inspection.',
    `minor_nonconformance_count` STRING COMMENT 'Number of minor non-conformances identified during the inspection. Minor findings require corrective action within a defined timeframe but do not automatically disqualify certification.',
    `notes` STRING COMMENT 'Free-text field for inspector observations, contextual remarks, environmental conditions at time of inspection, or other qualitative information not captured in structured fields.',
    `observation_count` STRING COMMENT 'Number of observations or recommendations noted during the inspection that do not constitute formal non-conformances but indicate areas for improvement.',
    `outcome` STRING COMMENT 'Overall pass/fail determination for the inspection event. Conditional pass indicates the operation may continue subject to corrective actions within a defined timeframe.. Valid values are `pass|fail|conditional_pass|pending`',
    `overall_score` DECIMAL(18,2) COMMENT 'Numeric score or percentage representing the aggregate compliance performance across all inspection criteria evaluated. Scoring methodology varies by inspection type (e.g., GLOBALG.A.P. percentage, SQF numeric grade).',
    `reinspection_date` DATE COMMENT 'Scheduled date for the follow-up re-inspection when reinspection_required is true. Used for compliance calendar management and audit scheduling.',
    `reinspection_required` BOOLEAN COMMENT 'Indicates whether a follow-up re-inspection is required to verify corrective action completion or to re-evaluate a failed inspection outcome.',
    `report_issued_date` DATE COMMENT 'Date on which the formal inspection report was issued to the inspected party. Starts the clock for corrective action response deadlines and certification validity periods.',
    `report_number` STRING COMMENT 'Official report number assigned by the regulatory body or certification organization to the formal inspection report document. Used for regulatory submission tracking and document management.',
    `scheduled_date` DATE COMMENT 'The planned calendar date on which the inspection was originally scheduled to occur, used for compliance planning and audit scheduling.',
    `standard_version` STRING COMMENT 'The specific version or edition of the certification standard applied during the inspection (e.g., GLOBALG.A.P. v5.4, SQF Edition 9). Critical for audit traceability as standards evolve.',
    `start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the inspection activity commenced on-site or in the facility, used for duration tracking and regulatory audit trails.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the inspection record was most recently modified. Supports change tracking, data lineage, and audit trail requirements.',
    CONSTRAINT pk_inspection PRIMARY KEY(`inspection_id`)
) COMMENT 'Master record for all quality inspections across field, post-harvest, storage, processing, and supply chain operations. Captures inspection type (GAP, GMP, HACCP verification, FSMA, GLOBALG.A.P., pre-operational, receiving, GAP compliance assessment), scope, facility or field location, scheduled and actual dates, inspector identity, overall pass/fail outcome, and score or grade. For GAP compliance assessments: standard version, module-level scoring (worker health, agricultural water, soil amendments, field sanitation, traceability), and certification eligibility. Regulatory body association (USDA, FDA, FSIS, APHIS). SSOT for all inspection events in the quality domain.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`inspection_finding` (
    `inspection_finding_id` BIGINT COMMENT 'Unique surrogate identifier for each individual inspection or audit finding record. Primary key for the inspection_finding data product in the quality domain SSOT.',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: MRL exceedance findings (mrl_exceedance_flag=true) must trace back to the specific EPA-registered agrochemical product. Regulatory reportable findings and corrective action prioritization require know',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the specific commodity lot or product batch associated with this finding, if applicable. Enables traceability from finding to affected product for recall management, COA linkage, and MRL compliance tracking.',
    `facility_id` BIGINT COMMENT 'Reference to the facility, farm site, processing plant, or storage location where this finding was identified. Supports facility-level compliance reporting and FSMA Preventive Controls facility registration linkage.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: GAP inspection findings (field sanitation, agricultural water, soil amendments) are scored per field. Linking inspection_finding to field enables field-level risk scoring and finding trend analysis — ',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Inspection findings are discovered during quality inspections. The inspection_finding table has inspection_area and audit_type fields suggesting findings can come from inspections. This FK links findi',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: When mrl_exceedance_flag is set on an inspection finding, the specific regulatory tolerance that was exceeded must be referenced for regulatory_reportable_flag determination, agency notification, and ',
    `event_id` BIGINT COMMENT 'Reference to the parent inspection or audit event that generated this finding. Links the finding to its originating quality event (inspection run, audit session, or certification visit).',
    `employee_id` BIGINT COMMENT 'Reference to the party (internal auditor, second-party customer auditor, or third-party certification body inspector) who identified and recorded this finding. Supports auditor qualification tracking and finding pattern analysis.',
    `prior_finding_inspection_finding_id` BIGINT COMMENT 'Reference to the earlier finding record that this finding is a recurrence of. Populated when repeat_finding_flag is True. Enables trend analysis and systemic non-conformance identification across audit cycles.',
    `quality_audit_id` BIGINT COMMENT 'Foreign key linking to quality.quality_audit. Business justification: Inspection findings can be discovered during formal quality audits (GFSI, GAP, etc.). The inspection_finding table has audit_type and standard_scheme fields that duplicate quality_audit master data. T',
    `safety_event_id` BIGINT COMMENT 'Foreign key linking to workforce.safety_event. Business justification: Inspection findings related to WPS violations, pesticide handler exposure, or worker safety GMP failures directly correspond to safety incidents. Agriculture regulators (EPA WPS, OSHA) require cross-r',
    `ccp_reference` STRING COMMENT 'Identifier of the HACCP Critical Control Point (CCP) associated with this finding, if applicable (e.g., CCP-01 Thermal Processing, CCP-02 Metal Detection). Links the finding to the HACCP plan for hazard analysis and corrective action tracking.',
    `certification_impact` STRING COMMENT 'Assessed impact of this finding on the facilitys or operations current certification status under the applicable GFSI scheme or GLOBALG.A.P. certification. Populated by the lead auditor or certification body. Drives certification status update workflows.. Valid values are `none|grade_reduction|conditional_pass|suspension|withdrawal`',
    `closure_due_date` DATE COMMENT 'Deadline by which the corrective action must be fully implemented and the finding verified as closed. Distinct from response_due_date (plan submission) — this is the implementation completion deadline. Used for certification readiness tracking.',
    `created_timestamp` TIMESTAMP COMMENT 'Audit timestamp when this finding record was first captured in the system. Used for data lineage, SLA tracking, and regulatory audit trails. Populated automatically on insert.',
    `detected_timestamp` TIMESTAMP COMMENT 'The principal real-world event timestamp when this finding was identified or observed during the inspection or audit. Distinct from record creation audit timestamp. Critical for PHI (Pre-Harvest Interval) and REI (Restricted Entry Interval) compliance timelines.',
    `disposition` STRING COMMENT 'The disposition decision for any product or material implicated by this finding. Applicable when the finding is associated with a specific commodity lot. Aligns with SAP QM usage decision codes and FSMA preventive controls disposition requirements.. Valid values are `accept|rework|reject|hold|destroy|release_with_deviation`',
    `evidence_document_reference` STRING COMMENT 'Reference identifier or URL to supporting evidence documents (photographs, laboratory test results, COA, temperature logs, pesticide application records) stored in the document management system. Supports audit trail completeness and regulatory submission packages.',
    `finding_classification` STRING COMMENT 'Severity classification of the finding per food safety and quality management standards. Critical = immediate food safety risk or regulatory violation; Major = significant non-conformance likely to result in product failure; Minor = partial non-conformance; Observation = noted deviation not yet non-conforming; Opportunity for Improvement (OFI) = best-practice recommendation. Drives corrective action urgency and certification impact.. Valid values are `critical|major|minor|observation|opportunity_for_improvement`',
    `finding_description` STRING COMMENT 'Detailed narrative description of the non-conformance, observation, or opportunity for improvement. Documents what was found, where, and under what conditions. Supports root cause analysis and corrective action planning.',
    `finding_number` STRING COMMENT 'Externally-known, human-readable business identifier for this finding (e.g., QF-2024-000123). Used in corrective action requests, audit reports, and regulatory submissions. Sourced from SAP QM notification numbering.. Valid values are `^QF-[0-9]{4}-[0-9]{6}$`',
    `finding_status` STRING COMMENT 'Current lifecycle state of the finding from identification through closure. Drives corrective action workflows and certification readiness dashboards. [ENUM-REF-CANDIDATE: open|under_review|corrective_action_pending|corrective_action_submitted|verified_closed|accepted|waived — promote to reference product]',
    `finding_title` STRING COMMENT 'Short, human-readable title summarizing the nature of the non-conformance or observation (e.g., Inadequate pest control records, CCP temperature log gap). Used in dashboards, corrective action requests, and management reports.',
    `food_safety_risk_flag` BOOLEAN COMMENT 'Indicates whether this finding poses a direct food safety risk requiring immediate escalation under HACCP or FSMA protocols. When True, triggers mandatory notification workflows to the food safety team and may require product hold or recall assessment.',
    `gap_gmp_category` STRING COMMENT 'Categorizes the finding within the GAP/GMP compliance framework. Supports structured reporting to USDA, FDA, and GLOBALG.A.P. certification bodies and enables category-level trend analysis for continuous improvement programs. [ENUM-REF-CANDIDATE: GAP|GMP|HACCP|sanitation|traceability|pest_control|water_quality|worker_health|equipment|documentation — promote to reference product]',
    `inspection_area` STRING COMMENT 'The physical area, zone, process step, or operational unit where the finding was identified (e.g., receiving dock, cold storage, processing line 3, field block A, irrigation system). Supports spatial analysis of non-conformance patterns.',
    `inspector_notes` STRING COMMENT 'Free-text field for additional contextual notes, observations, or recommendations recorded by the inspector or auditor at the time of the finding. Supplements the structured finding_description with qualitative context for root cause analysis.',
    `ipm_related_flag` BOOLEAN COMMENT 'Indicates whether this finding is related to Integrated Pest Management (IPM) program compliance, including pest scouting records, pesticide application logs, PHI (Pre-Harvest Interval) adherence, or REI (Restricted Entry Interval) compliance.',
    `mrl_exceedance_flag` BOOLEAN COMMENT 'Indicates whether this finding involves a pesticide or chemical residue exceeding the Maximum Residue Limit (MRL) as defined by EPA, Codex Alimentarius, or importing country regulations. Triggers mandatory product hold and regulatory notification.',
    `objective_evidence` STRING COMMENT 'Factual, verifiable evidence supporting the finding — records reviewed, measurements taken, observations made, or interviews conducted. Required by ISO 19011 and all GFSI scheme auditing protocols to substantiate the finding classification.',
    `parent_event_type` STRING COMMENT 'Discriminator indicating whether the parent event was a quality inspection (routine operational check) or a formal audit (internal, second-party, or third-party certification audit). Drives workflow routing and reporting.. Valid values are `inspection|audit`',
    `regulatory_agency` STRING COMMENT 'The regulatory authority to which this finding must be reported, if regulatory_reportable_flag is True. Determines the specific reporting format, timeline, and submission channel required. [ENUM-REF-CANDIDATE: USDA|FDA|FSIS|EPA|APHIS|OSHA|state_agency|none — 8 candidates stripped; promote to reference product]',
    `regulatory_reportable_flag` BOOLEAN COMMENT 'Indicates whether this finding must be reported to a regulatory authority (USDA, FDA, FSIS, EPA, APHIS). When True, triggers mandatory regulatory notification workflows and documentation requirements under FSMA, FSIS directives, or EPA regulations.',
    `repeat_finding_flag` BOOLEAN COMMENT 'Indicates whether this finding is a recurrence of a previously identified non-conformance at the same location or process. Repeat findings trigger escalated corrective action requirements under GFSI schemes and may impact certification grade.',
    `response_due_date` DATE COMMENT 'Required deadline by which a corrective action plan or response must be submitted for this finding. Determined by finding classification and standard scheme requirements (e.g., critical findings typically require 24-hour response; major findings 30 days). Drives SLA monitoring.',
    `risk_severity_rating` STRING COMMENT 'Risk-based severity assessment of the findings potential impact on food safety, product quality, regulatory compliance, or business continuity. Distinct from finding_classification (which is scheme-defined); this is the internal risk management rating used for prioritization and HACCP hazard analysis alignment.. Valid values are `critical|high|medium|low`',
    `sap_qm_notification_number` STRING COMMENT 'The SAP S/4HANA QM module notification number corresponding to this finding. Enables bidirectional traceability between the lakehouse silver layer record and the operational system of record for corrective action management and ERP integration.',
    `standard_clause_reference` STRING COMMENT 'The specific clause, control point, element, or requirement number within the applicable standard scheme against which this finding was raised (e.g., FSMA 21 CFR Part 117.135, GLOBALG.A.P. CB.7.1, SQF Element 2.4.3, BRC Clause 4.11.2, IFS Requirement 4.18.1). Essential for certification body reporting and corrective action traceability.',
    `updated_timestamp` TIMESTAMP COMMENT 'Audit timestamp when this finding record was last modified. Tracks changes to status, corrective action assignments, or evidence updates for compliance audit trail purposes.',
    `verified_closed_date` DATE COMMENT 'Actual date on which the finding was verified as effectively closed following corrective action implementation. Populated by the verifying auditor or quality manager. Used to calculate closure cycle time and assess corrective action effectiveness.',
    CONSTRAINT pk_inspection_finding PRIMARY KEY(`inspection_finding_id`)
) COMMENT 'Individual findings, observations, and deficiencies identified during quality inspections or formal audits (internal, second-party, third-party certification). Records parent event reference and type (inspection or audit), finding classification (critical, major, minor, observation, opportunity for improvement), applicable standard clause reference (FSMA 21 CFR Part 117, GLOBALG.A.P. control point, SQF Element, BRC Clause, IFS requirement), description of non-conformance or observation, objective evidence, risk severity rating, required response timeline, and disposition. Unified SSOT for ALL quality findings regardless of detection context — replaces separate audit finding tracking. Drives corrective action generation and certification status updates.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`corrective_action` (
    `corrective_action_id` BIGINT COMMENT 'Unique system-generated identifier for the Corrective and Preventive Action (CAPA) record. Primary key for the corrective_action data product in the quality domain.',
    `alert_id` BIGINT COMMENT 'Foreign key linking to weather.weather_alert. Business justification: CAPAs triggered by weather-caused quality events (spray drift from high winds, contamination from flooding) must reference the weather alert for root cause documentation. FSMA preventive controls and ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: CAPA execution in agriculture incurs labor, materials, and process-change costs charged to cost centers. Cost-of-quality management accounting and CAPA ROI analysis require tracking CAPA expenditures ',
    `facility_id` BIGINT COMMENT 'Identifier of the facility, processing plant, farm site, or warehouse where the nonconformance or finding originated and where the corrective action is to be implemented. Links to the facility master record.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: GAP and FSMA corrective actions are frequently field-specific (e.g., cease irrigation from contaminated source on field X, implement buffer zone on field Y). Linking corrective_action to field enables',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: CAPA remediation expenditures (equipment cleaning, retesting, process upgrades) are posted to GL accounts. Financial period-close and cost-of-quality P&L reporting in agriculture require CAPA costs ma',
    `inspection_finding_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_finding. Business justification: Corrective actions (CAPAs) are generated in response to inspection findings. The corrective_action table has source_type and source_reference_number (string-based) but lacks structured FK to findings.',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: corrective_action has source_type (STRING) and source_reference_id (BIGINT) as a polymorphic reference. When source_type = inspection, adding a typed inspection_id FK provides a direct reference to ',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: CAPAs triggered by MRL exceedances must reference the specific regulatory tolerance to document the preventive action scope, verify effectiveness against the threshold, and satisfy FSMA Preventive Con',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Corrective actions are initiated in response to nonconformances. The corrective_action table has source_type and source_reference_number (string-based) but lacks structured FK to nonconformance. This ',
    `parent_capa_corrective_action_id` BIGINT COMMENT 'Reference to a parent CAPA record when this CAPA was generated as a follow-up due to ineffective closure of a prior action. Enables CAPA lineage tracking and recurrence chain analysis.',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: CAPAs for precipitation-caused contamination events (runoff into water sources, flooding of storage areas) require direct reference to the precipitation event for FSMA root cause analysis and regulato',
    `employee_id` BIGINT COMMENT 'Identifier of the employee or team lead assigned as the primary owner accountable for implementing the corrective and preventive action. Links to the workforce/employee master record in SAP SuccessFactors.',
    `quality_audit_id` BIGINT COMMENT 'Foreign key linking to quality.audit. Business justification: corrective_action has source_type (STRING) and source_reference_id (BIGINT) as a polymorphic reference. When source_type = audit, adding a typed audit_id FK provides a direct reference to the audit ',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: CAPAs raised to address sustainability certification nonconformances (Rainforest Alliance, ISCC, organic) must be tracked against the specific certification. Certification bodies require documented CA',
    `training_event_id` BIGINT COMMENT 'Foreign key linking to workforce.training_event. Business justification: Under FSMA preventive controls and GFSI schemes, corrective actions frequently mandate a specific training event as the preventive measure. Linking CAPA records to the fulfilling training event is req',
    `vendor_audit_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_audit. Business justification: Vendor audit findings are a primary source of CAPAs in agriculture supplier management. The corrective_action.source_reference_id is generic; a dedicated vendor_audit_id FK enables direct traceability',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Supplier Corrective Action Requests (SCARs) are a named agriculture procurement process where CAPAs are formally issued to vendors. Quality teams must link a CAPA to the responsible vendor for SCAR tr',
    `actual_closure_date` DATE COMMENT 'Actual date on which all corrective and preventive actions were fully implemented and the CAPA record was formally closed following successful verification. Compared against target_completion_date to measure on-time closure performance.',
    `capa_number` STRING COMMENT 'Externally-known business identifier for the CAPA record, formatted as CAPA-{YEAR}-{SEQUENCE}. Used for cross-referencing in audit reports, regulatory submissions, and SAP QM notification workflows.. Valid values are `^CAPA-[0-9]{4}-[0-9]{6}$`',
    `capa_status` STRING COMMENT 'Current lifecycle status of the CAPA record, tracking progression from initial opening through root cause analysis, implementation, verification, and closure. Drives workflow routing in SAP S/4HANA QM.. Valid values are `open|in_progress|pending_verification|closed|overdue|cancelled`',
    `capa_type` STRING COMMENT 'Classifies whether the action is purely corrective (addressing an existing nonconformance), purely preventive (addressing a potential risk), or both. Determines reporting category for FSMA, SQF, BRC, and IFS compliance.. Valid values are `corrective|preventive|both`',
    `certification_standard` STRING COMMENT 'The food safety or agricultural certification standard under which this CAPA was generated or is required to be documented. Determines the specific documentation and closure requirements applicable to the CAPA. [ENUM-REF-CANDIDATE: SQF|BRC|IFS|GLOBALG.A.P.|FSMA|HACCP|ISO_22000|USDA_NOP|other — promote to reference product]. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|FSMA|HACCP|ISO_22000|USDA_NOP|other`',
    `corrective_action_description` STRING COMMENT 'Detailed description of the specific corrective action(s) taken to eliminate the identified root cause and prevent recurrence of the nonconformance. Documents what was done, how it was done, and the expected outcome.',
    `created_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording when the CAPA record was first created in the data platform. Used for data lineage, audit trail, and silver layer ingestion tracking.',
    `department` STRING COMMENT 'Name of the department or operational area responsible for implementing the corrective and preventive action (e.g., Quality Assurance, Production, Procurement, Logistics). Used for workload assignment and KPI reporting.',
    `effectiveness_review_date` DATE COMMENT 'Date on which the effectiveness review was conducted to assess whether the implemented corrective and preventive actions successfully eliminated the root cause and prevented recurrence of the nonconformance.',
    `effectiveness_review_notes` STRING COMMENT 'Narrative notes from the effectiveness review, documenting evidence reviewed, observations made, and rationale for the effectiveness determination. Supports audit trail and continuous improvement documentation.',
    `effectiveness_review_outcome` STRING COMMENT 'Outcome of the post-implementation effectiveness review, assessing whether the corrective and preventive actions successfully eliminated the root cause and prevented recurrence. A not_effective outcome triggers a new CAPA cycle.. Valid values are `effective|partially_effective|not_effective|pending_review`',
    `finding_description` STRING COMMENT 'Detailed narrative description of the nonconformance, inspection finding, audit observation, or food safety incident that triggered this CAPA. Provides the factual basis for root cause analysis and corrective action planning.',
    `fsma_reportable_flag` BOOLEAN COMMENT 'Indicates whether this CAPA is associated with a food safety event that requires reporting or documentation under the Food Safety Modernization Act (FSMA), including Preventive Controls, Produce Safety, or Foreign Supplier Verification Program requirements.',
    `gap_gmp_violation_flag` BOOLEAN COMMENT 'Indicates whether the nonconformance or finding that triggered this CAPA constitutes a violation of Good Agricultural Practices (GAP) or Good Manufacturing Practices (GMP). Flags records requiring mandatory regulatory reporting.',
    `haccp_ccp_reference` STRING COMMENT 'Reference to the specific HACCP Critical Control Point (CCP) or Preventive Control associated with this CAPA, where applicable. Links the corrective action to the HACCP plan for food safety traceability and regulatory compliance.',
    `immediate_containment_action` STRING COMMENT 'Description of the immediate containment or disposition action taken at the time of the finding to prevent affected product from reaching the market or causing further harm (e.g., product quarantine, lot hold, process stoppage). Distinct from the root-cause-based corrective action.',
    `opened_timestamp` TIMESTAMP COMMENT 'Date and time when the CAPA record was formally opened and entered into the quality management system. Represents the principal business event timestamp for the CAPA lifecycle. Used for aging analysis and regulatory timeliness reporting.',
    `preventive_action_description` STRING COMMENT 'Detailed description of the systemic preventive action(s) implemented to eliminate the potential cause of a nonconformance or to prevent recurrence across similar processes, products, or facilities. Addresses systemic risk beyond the immediate corrective fix.',
    `priority` STRING COMMENT 'Business priority level assigned to the CAPA based on the severity of the finding, food safety risk, regulatory impact, and potential for recurrence. Drives escalation thresholds and target completion timelines.. Valid values are `critical|high|medium|low`',
    `recurrence_flag` BOOLEAN COMMENT 'Indicates whether this CAPA addresses a recurring nonconformance or finding that has been previously documented. Recurring issues trigger escalated review and systemic corrective action requirements under GFSI standards.',
    `regulatory_requirement` STRING COMMENT 'Specific regulatory clause, standard requirement, or certification criterion that the CAPA addresses (e.g., FSMA 21 CFR Part 117.150, GLOBALG.A.P. IFA v6 AF 4.1, SQF Element 2.5.3). Supports regulatory reporting and audit readiness.',
    `responsible_party_name` STRING COMMENT 'Full name of the employee or team lead assigned as the primary owner of the CAPA. Stored for audit trail and regulatory reporting purposes where the named individual must be identified in compliance documentation.',
    `root_cause_category` STRING COMMENT 'High-level classification of the root cause to enable trend analysis and systemic issue identification across the quality management system. Categories align with standard fishbone/Ishikawa diagram branches used in agricultural food safety programs.. Valid values are `people|process|equipment|material|environment|management_system`',
    `root_cause_description` STRING COMMENT 'Detailed narrative of the identified root cause(s) of the nonconformance or finding, as determined through the selected root cause analysis method. Forms the foundation for corrective and preventive action planning.',
    `root_cause_method` STRING COMMENT 'Structured methodology used to identify the root cause of the nonconformance or finding. Common methods include 5-Why analysis, fishbone (Ishikawa) diagram, fault tree analysis, Failure Mode and Effects Analysis (FMEA), Pareto analysis, or brainstorming. [ENUM-REF-CANDIDATE: 5_why|fishbone|fault_tree|failure_mode_effects_analysis|pareto|brainstorming|other — promote to reference product]',
    `sap_qm_notification_number` STRING COMMENT 'SAP S/4HANA QM module notification number associated with this CAPA record. Enables bidirectional traceability between the lakehouse silver layer and the operational SAP QM workflow system.',
    `source_reference_number` STRING COMMENT 'Human-readable business identifier of the originating record (e.g., nonconformance report number, audit finding reference, inspection report number). Supports cross-document traceability in regulatory submissions and audit packages.',
    `source_type` STRING COMMENT 'Categorizes the originating trigger for the CAPA record. Indicates whether the action was initiated from an inspection finding, nonconformance report, audit finding, environmental monitoring positive, customer complaint, Maximum Residue Limit (MRL) exceedance, food safety incident, or internal observation. [ENUM-REF-CANDIDATE: inspection_finding|nonconformance|audit_finding|environmental_monitoring|customer_complaint|mrl_exceedance|food_safety_incident|internal_observation — promote to reference product]',
    `target_completion_date` DATE COMMENT 'Planned date by which all corrective and preventive actions must be fully implemented and ready for verification. Used for overdue tracking, escalation management, and regulatory audit readiness reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'System-generated timestamp recording when the CAPA record was last modified in the data platform. Supports change tracking, audit trail requirements, and incremental data pipeline processing.',
    `verification_date` DATE COMMENT 'Date on which the verification activity was performed to confirm that the corrective and preventive actions were implemented as planned and are effective.',
    `verification_method` STRING COMMENT 'Description of the method used to verify that the corrective and preventive actions were effectively implemented (e.g., re-inspection, laboratory testing, process audit, document review, observation). Required for FSMA, SQF, BRC, and IFS closure documentation.',
    CONSTRAINT pk_corrective_action PRIMARY KEY(`corrective_action_id`)
) COMMENT 'CAPA (Corrective and Preventive Action) records generated in response to inspection findings, nonconformances (including MRL exceedances and food safety incidents), audit findings, or environmental monitoring positives. Tracks root cause analysis method (5-Why, fishbone, fault tree), corrective action description, preventive action description, responsible party, target completion date, actual closure date, verification method and date, effectiveness review outcome and review date. Supports FSMA, SQF, BRC, and IFS CAPA requirements. Integrates with SAP S/4HANA QM notification workflows. Links to originating finding or nonconformance for full traceability.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`nonconformance` (
    `nonconformance_id` BIGINT COMMENT 'Unique system-generated identifier for each nonconformance record. Primary key for the nonconformance master record in the quality management system.',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: Nonconformances for MRL exceedances currently store pesticide_active_ingredient as denormalized text. Linking to agrochemical_product enables traceability to the EPA-registered product, supports recal',
    `alert_id` BIGINT COMMENT 'Foreign key linking to weather.weather_alert. Business justification: Severe weather alerts (hail, flooding, high winds) directly trigger quality nonconformances. Linking NC to the causative weather alert supports root cause documentation required by GFSI schemes, FSMA ',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Nonconformance disposal, rework, and retesting costs are charged to cost centers in agricultural operations. Cost-of-quality reporting by farm unit or facility requires this link for management accoun',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: When a nonconformance (MRL exceedance, food safety incident) affects product allocated to a specific buyer, customer notification is a regulatory and commercial obligation under FSMA and trade contrac',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: MRL exceedances, contaminated water sources, and soil amendment violations in agriculture are traced to specific fields. Linking nonconformance to field enables field-level root cause analysis and sup',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Frost events cause crop damage nonconformances (freeze injury affecting commodity grade, food safety implications of damaged produce). Direct link supports root cause analysis in FSMA incident reports',
    `inspection_finding_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_finding. Business justification: Nonconformances are often triggered by specific inspection findings. The nonconformance table has detection_source (string) but lacks a structured FK to the finding that triggered it. This FK enables ',
    `material_master_id` BIGINT COMMENT 'Reference to the material master record for the commodity, product, or input material involved in the nonconformance.',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: Nonconformance stores applicable_mrl_standard and mrl_threshold_mg_kg as denormalized text/numeric. Linking to mrl_threshold normalizes the regulatory tolerance reference, enabling FSMA reportability ',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Precipitation events (flooding, runoff, hail) directly cause quality nonconformances (contamination, physical damage). Linking NC to the triggering precipitation event is required for FSMA root cause ',
    `procurement_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Nonconformances on incoming goods are detected at goods receipt. Linking NC to the specific GRN enables three-way match dispute resolution, return claim processing, and lot traceability back to the de',
    `quality_audit_id` BIGINT COMMENT 'Foreign key linking to quality.audit. Business justification: When a nonconformance is detected during a formal audit (detection_source = audit), adding audit_id FK provides a direct typed reference to the audit record. nonconformance has gap_audit_finding_ref',
    `trial_id` BIGINT COMMENT 'Foreign key linking to research.trial. Business justification: Trial-linked nonconformance tracking is a named QA process in ag research: MRL exceedances, GMO containment breaches, or protocol deviations during a trial must be traceable to the specific trial for ',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: When received agricultural inputs (seeds, chemicals, commodities) fail quality inspection, the supplying vendor must be identified for SCAR issuance, vendor scorecard deduction, return claim initiatio',
    `affected_export_market` STRING COMMENT 'ISO 3-letter country code(s) of export markets impacted by the MRL exceedance or food safety incident. Drives market withdrawal decisions and trade compliance actions.',
    `affected_quantity` DECIMAL(18,2) COMMENT 'Total quantity of product, commodity, or material affected by the nonconformance, expressed in the unit of measure specified in quantity_uom.',
    `affected_value_usd` DECIMAL(18,2) COMMENT 'Estimated financial value of the affected product or commodity in US dollars. Used for financial impact assessment, insurance claims, and EBITDA impact reporting.',
    `commodity_code` STRING COMMENT 'Standardized commodity or crop code identifying the agricultural product involved (e.g., USDA commodity code, internal SKU). Enables cross-product nonconformance trend analysis.',
    `corrective_action_closed_date` DATE COMMENT 'Actual date on which the corrective action was verified as complete and effective. Marks closure of the CAPA cycle for this nonconformance.',
    `corrective_action_description` STRING COMMENT 'Description of the corrective and preventive action (CAPA) implemented or planned to address the root cause and prevent recurrence of the nonconformance.',
    `corrective_action_due_date` DATE COMMENT 'Target completion date for the corrective action. Used for CAPA tracking, audit follow-up scheduling, and regulatory compliance deadline management.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the nonconformance record was first created in the quality management system. Supports audit trail, regulatory reporting timelines, and data lineage.',
    `detected_residue_level` DECIMAL(18,2) COMMENT 'Measured pesticide residue concentration in mg/kg (ppm) as determined by laboratory analysis. Populated for nonconformance_type = mrl_exceedance. Compared against applicable MRL standard.',
    `detection_date` DATE COMMENT 'Calendar date on which the nonconformance was first identified or detected. Used for regulatory reporting timelines and corrective action due date calculations.',
    `detection_point` STRING COMMENT 'Stage in the production or supply chain where the nonconformance was detected. Supports root cause analysis and process improvement targeting. [ENUM-REF-CANDIDATE: receiving|in_process|finished_goods|storage|dispatch|field|customer_complaint|audit|laboratory — promote to reference product]',
    `detection_source` STRING COMMENT 'Origin or mechanism by which the nonconformance was identified. Distinguishes proactive internal detection from reactive external discovery. [ENUM-REF-CANDIDATE: internal_audit|external_audit|laboratory_test|operator_observation|customer_complaint|regulatory_inspection|supplier_notification|automated_sensor — promote to reference product]',
    `disposition_date` DATE COMMENT 'Date on which the disposition decision was formally approved and recorded. Required for regulatory audit trails and FSMA compliance documentation.',
    `disposition_decision` STRING COMMENT 'Final quality disposition decision for the nonconforming product or material. Determines the fate of affected inventory and drives downstream supply chain and financial actions.. Valid values are `release|rework|regrade|destroy|return_to_supplier|hold_pending`',
    `food_safety_incident_subtype` STRING COMMENT 'Specific category of food safety incident. Populated only when nonconformance_type = food_safety_incident. Drives HACCP critical control point review and regulatory reporting requirements.. Valid values are `contamination|foreign_material|allergen|pathogen|chemical`',
    `gap_audit_finding_ref` STRING COMMENT 'Reference number linking this nonconformance to a specific GAP or GMP audit finding. Enables traceability between audit programs and resulting nonconformance records.',
    `gfsi_scheme` STRING COMMENT 'GFSI-benchmarked certification scheme under which this nonconformance was identified or is being managed. Determines applicable audit standard requirements for CAPA and closure.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|FSSC22000|not_applicable`',
    `hazard_classification` STRING COMMENT 'HACCP hazard classification for food safety incidents. Categorizes the nature of the food safety hazard to guide risk assessment and control measure selection.. Valid values are `biological|chemical|physical|radiological`',
    `incident_closure_status` STRING COMMENT 'Detailed closure workflow status for food safety incidents and major nonconformances. Tracks progression from initial detection through CAPA verification and regulatory sign-off.. Valid values are `open|capa_in_progress|capa_verified|closed|regulatory_pending`',
    `lot_number` STRING COMMENT 'Human-readable batch or lot number of the affected product or commodity. Critical for traceability, recall execution, and regulatory reporting under FSMA.',
    `mock_recall_flag` BOOLEAN COMMENT 'Indicates whether this record represents a mock/simulated recall exercise rather than an actual recall event. Required for GFSI, SQF, BRC, and GLOBALG.A.P. certification audit readiness.',
    `nc_status` STRING COMMENT 'Current lifecycle status of the nonconformance record within the quality management workflow.. Valid values are `open|under_investigation|pending_disposition|closed|escalated`',
    `nonconformance_type` STRING COMMENT 'Classification of the nonconformance category. product = physical product defect; process = deviation from SOP/GMP; system = management system gap; mrl_exceedance = Maximum Residue Limit (MRL) exceedance; food_safety_incident = HACCP/FSMA food safety event.. Valid values are `product|process|system|mrl_exceedance|food_safety_incident`',
    `qm_notification_number` STRING COMMENT 'External quality notification number from SAP S/4HANA QM module (Q-notification). Serves as the cross-system business identifier for this nonconformance record.',
    `quantity_uom` STRING COMMENT 'Unit of measure for the affected quantity. Supports MT (Metric Ton), BU (Bushel), CWT (Hundredweight), KG, LB, L, GAL, UNIT, CASE per agricultural industry standards. [ENUM-REF-CANDIDATE: MT|BU|CWT|KG|LB|L|GAL|UNIT|CASE — 9 candidates stripped; promote to reference product]',
    `recall_class` STRING COMMENT 'FDA/USDA recall classification. Class I = serious adverse health consequences or death; Class II = temporary adverse health consequences; Class III = unlikely to cause adverse health consequences. Populated for food safety incidents requiring recall.. Valid values are `I|II|III|not_applicable`',
    `regulatory_agencies_notified` STRING COMMENT 'Comma-separated list of regulatory agencies formally notified of this nonconformance (e.g., FDA, USDA, FSIS, EPA, APHIS). Populated when regulatory_notification_required is True.',
    `regulatory_notification_required` BOOLEAN COMMENT 'Indicates whether this nonconformance triggers a mandatory regulatory notification obligation to USDA, FDA, FSIS, EPA, or APHIS. Drives compliance workflow escalation.',
    `reported_by` STRING COMMENT 'Name or employee identifier of the person who initially reported or raised the nonconformance. Supports accountability tracking and audit trail requirements.',
    `root_cause_category` STRING COMMENT 'High-level categorization of the identified root cause of the nonconformance. Supports trend analysis, corrective action prioritization, and CAPA program management. [ENUM-REF-CANDIDATE: raw_material|process_deviation|equipment_failure|human_error|supplier_issue|environmental|pest_contamination|storage_condition — promote to reference product]',
    `root_cause_description` STRING COMMENT 'Detailed narrative description of the identified root cause following investigation. Supports 5-Why or fishbone analysis documentation for CAPA and audit evidence.',
    `severity_level` STRING COMMENT 'Risk-based severity classification of the nonconformance. minor = low risk, no regulatory impact; major = significant deviation requiring corrective action; critical = immediate risk to product integrity or compliance; food_safety_crisis = imminent public health risk requiring recall or regulatory notification.. Valid values are `minor|major|critical|food_safety_crisis`',
    `sku` STRING COMMENT 'Stock Keeping Unit identifier for the finished product or processed commodity involved in the nonconformance. Used for traceability and market withdrawal coordination.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent update to the nonconformance record. Supports change tracking, audit trail integrity, and data lineage in the Databricks Silver layer.',
    CONSTRAINT pk_nonconformance PRIMARY KEY(`nonconformance_id`)
) COMMENT 'Unified master record for all quality failures, deviations, and food safety incidents across crop production, livestock operations, processing, and supply chain. Captures nonconformance type (product, process, system, MRL_exceedance, food_safety_incident), severity level (minor, major, critical, food_safety_crisis), affected lot, commodity or product SKU, detection point and source. For standard nonconformances: disposition decision, financial impact estimate, regulatory notification flag. For MRL-type: pesticide active ingredient, detected residue level, applicable MRL standard (EPA, EU, Codex), exceedance magnitude, affected export market. For food safety incidents: incident subtype (contamination, foreign material, allergen, pathogen, chemical), hazard classification, recall class (I, II, III), mock recall flag, affected quantity and value, regulatory agencies notified, root cause category, and incident closure status. SSOT for ALL quality failures from minor process deviations through food safety crises, recalls, and market withdrawals.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`certificate_of_analysis` (
    `certificate_of_analysis_id` BIGINT COMMENT 'Primary key for certificate_of_analysis',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: COAs in agriculture are issued to specific buyers for commodity lots they are purchasing. The COA issuance to buyer process is fundamental — customers require COAs before accepting delivery. Linking',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: COAs issue a USDA grade determination (usda_grade stored as denormalized text). Linking to grading_standard normalizes the grade reference, enabling buyer contract compliance verification, USDA AMS gr',
    `laboratory_id` BIGINT COMMENT 'Foreign key linking to quality.laboratory. Business justification: COAs are issued by specific laboratories. The COA table has issuing_lab_name and lab_accreditation_number (strings) but lacks structured FK. This FK enables joining to get complete laboratory details ',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: COA mrl_compliant flag and pesticide_residue_result_ppm require reference to the specific regulatory tolerance for the active ingredient/commodity/jurisdiction combination. Export market compliance (E',
    `authorized_by` STRING COMMENT 'Name or identifier of the qualified person (laboratory director, quality manager, or authorized signatory) who approved and released this COA. Required for GFSI audit documentation and regulatory traceability.',
    `coa_number` STRING COMMENT 'Externally-visible, human-readable identifier for the COA document as issued by the laboratory or quality department. Used on customer-facing documentation and GFSI audit packages.. Valid values are `^COA-[A-Z0-9]{4,20}$`',
    `coa_status` STRING COMMENT 'Current lifecycle status of the COA document. released indicates the COA is approved for customer-facing distribution. superseded indicates a newer version has replaced this record. Drives SAP QM usage decision workflow.. Valid values are `draft|pending_review|approved|released|rejected|superseded`',
    `commodity_type` STRING COMMENT 'Classification of the agricultural commodity or product covered by this COA (e.g., grain, oilseed, fresh produce, livestock product, processed food, agricultural input). [ENUM-REF-CANDIDATE: grain|oilseed|fresh_produce|livestock_product|processed_food|agricultural_input|feed|fertilizer|pesticide — promote to reference product]',
    `country_of_origin` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code indicating the country where the commodity was produced or harvested. Required for COOL (Country of Origin Labeling) compliance under USDA AMS regulations.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this COA record was first created in the system. Audit trail field supporting FSMA record-keeping requirements and GFSI documentation retention policies.',
    `expiry_date` DATE COMMENT 'Date after which the COA is no longer considered valid for commercial or regulatory purposes. Typically tied to product shelf life or certification validity period.',
    `gfsi_scheme` STRING COMMENT 'GFSI-recognized food safety certification scheme under which this COA was generated or which governs the testing requirements (SQF, BRC, IFS, FSSC 22000, GLOBALG.A.P.). Determines applicable testing protocols and documentation standards.. Valid values are `SQF|BRC|IFS|FSSC_22000|GLOBALG.A.P.|none`',
    `gmo_status` STRING COMMENT 'GMO testing result for the lot. identity_preserved indicates the lot has been maintained under IP (Identity Preserved) protocols from seed to shipment. Required for EU export documentation and non-GMO customer specifications.. Valid values are `gmo_free|gmo_detected|not_tested|identity_preserved`',
    `haccp_ccp_compliant` BOOLEAN COMMENT 'Indicates whether all HACCP Critical Control Point (CCP) parameters tested in this COA are within established critical limits. False triggers mandatory corrective action under FSMA Preventive Controls and FSIS HACCP regulations.',
    `heavy_metal_type` STRING COMMENT 'Specific heavy metal analyte tested. Each metal has distinct regulatory maximum levels under FDA, Codex Alimentarius, and EU regulations requiring separate tracking.. Valid values are `lead|cadmium|arsenic|mercury|total_heavy_metals`',
    `heavy_metals_result_ppm` DECIMAL(18,2) COMMENT 'Measured concentration of heavy metal contaminants (lead, cadmium, arsenic, mercury) in parts per million. Compared against FDA and Codex Alimentarius maximum levels for food safety compliance.',
    `issue_date` DATE COMMENT 'Date on which the Certificate of Analysis was formally issued and signed off by the authorized laboratory or quality manager. This is the principal business event date for the COA document lifecycle.',
    `microbial_result` DECIMAL(18,2) COMMENT 'Measured microbial count expressed as colony forming units per gram (CFU/g). Covers total plate count, E. coli, Salmonella, Listeria, and other pathogens per HACCP critical control point specifications.',
    `microbial_test_type` STRING COMMENT 'Specific microbiological analyte or pathogen tested. Salmonella and Listeria are HACCP critical control point parameters under FSMA Preventive Controls and FSIS regulations.. Valid values are `total_plate_count|e_coli|salmonella|listeria|coliforms|yeast_mold`',
    `moisture_pct` DECIMAL(18,2) COMMENT 'Measured moisture content of the commodity expressed as a percentage of total weight. Critical quality parameter for grain storage, mold prevention, and commodity grading under USDA AMS standards.',
    `mrl_compliant` BOOLEAN COMMENT 'Indicates whether all pesticide residue results are within the applicable Maximum Residue Limits (MRL) for the target market. True = compliant; False = MRL exceedance detected. Critical for export certification and GLOBALG.A.P. audit readiness.',
    `mycotoxin_result_ppb` DECIMAL(18,2) COMMENT 'Measured concentration of mycotoxins (aflatoxin, deoxynivalenol, fumonisin, ochratoxin, zearalenone) in parts per billion (ppb). Compared against FDA action levels and EU MRL limits for regulatory compliance.',
    `mycotoxin_type` STRING COMMENT 'Specific mycotoxin analyte tested in this COA record. Different mycotoxins have distinct FDA action levels and MRL thresholds under Codex Alimentarius and EU regulations.. Valid values are `aflatoxin|deoxynivalenol|fumonisin|ochratoxin_a|zearalenone|total_mycotoxin`',
    `overall_result` STRING COMMENT 'Aggregate pass/fail determination across all analytical parameters tested. A single fail on any critical parameter (e.g., MRL exceedance, mycotoxin above regulatory limit) results in an overall fail. Drives the release_status decision.. Valid values are `pass|fail|conditional_pass|pending`',
    `pesticide_residue_result_ppm` DECIMAL(18,2) COMMENT 'Measured pesticide residue concentration in parts per million (ppm). Compared against EPA-established Maximum Residue Limits (MRL) and Codex Alimentarius MRL tables for regulatory compliance and export eligibility.',
    `phi_compliant` BOOLEAN COMMENT 'Indicates whether the required Pre-Harvest Interval (PHI) was observed between the last pesticide application and harvest date. True = PHI observed; False = potential PHI violation. Verified against protection_event records.',
    `product_description` STRING COMMENT 'Full descriptive name of the commodity or product as it appears on the COA document, including variety, grade, or specification designation where applicable.',
    `protein_pct` DECIMAL(18,2) COMMENT 'Measured protein content of the commodity expressed as a percentage of dry weight. Key nutritional and commercial quality parameter for grain, feed, and food ingredient specifications.',
    `release_status` STRING COMMENT 'Indicates whether the lot covered by this COA has been approved for customer shipment and commercial release. blocked prevents order fulfillment in SAP SD. Distinct from coa_status which tracks the document lifecycle.. Valid values are `unreleased|released|blocked|conditionally_released`',
    `test_date` DATE COMMENT 'Date on which laboratory analysis was performed on the sample. Used to determine result validity windows and compliance with regulatory testing timelines.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this COA record. Supports audit trail requirements and change management tracking for regulatory documentation integrity.',
    CONSTRAINT pk_certificate_of_analysis PRIMARY KEY(`certificate_of_analysis_id`)
) COMMENT 'Certificate of Analysis (COA) master records for agricultural commodities, processed products, and inputs. Captures issuing laboratory, sample lot reference (LOT), commodity type, test date, analytical parameters tested (moisture, protein, mycotoxin, pesticide residue, heavy metals, microbial counts), pass/fail status per parameter, MRL compliance flags, and customer-facing release status. Integrates with SAP QM usage decision and supports GFSI certification documentation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`lab_sample` (
    `lab_sample_id` BIGINT COMMENT 'Unique system-generated identifier for each laboratory sample submission record. Primary key for the lab_sample data product in the quality domain.',
    `employee_id` BIGINT COMMENT 'Reference to the employee or field technician who physically collected the sample. Required for chain-of-custody documentation and FSMA traceability.',
    `facility_id` BIGINT COMMENT 'Reference to the facility, farm, processing plant, or warehouse location where the sample was collected. Supports geographic traceability and regulatory site-level reporting.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: Field-level lab sampling for pesticide residues, heavy metals, and microbial contamination is a core GAP and FSMA compliance practice. Linking lab_sample to field enables field-level quality history a',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: lab_sample has haccp_ccp_flag (BOOLEAN) indicating the sample is associated with a HACCP Critical Control Point. Adding haccp_plan_id FK links the sample to the specific HACCP plan and CCP it monitors',
    `inspection_lot_id` BIGINT COMMENT 'Reference to the SAP QM inspection lot under which this sample was collected. Links the lab sample to the broader quality inspection event in the ERP system.',
    `laboratory_id` BIGINT COMMENT 'Reference to the internal or external laboratory assigned to perform testing on this sample. Supports laboratory accreditation tracking and COA generation.',
    `land_soil_sample_id` BIGINT COMMENT 'Foreign key linking to land.soil_sample. Business justification: When agronomic soil samples are submitted for pesticide residue, heavy metals, or pathogen testing (organic certification, FSMA compliance), the quality lab_sample must reference the originating land.',
    `procurement_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Incoming goods sampling (pesticide residues, mycotoxins, germination rates) is triggered at goods receipt in agriculture. lab_sample.inspection_lot_id is unlinked and generic; a dedicated procurement_',
    `spray_window_id` BIGINT COMMENT 'Foreign key linking to weather.spray_window. Business justification: Lab samples collected for PHI/REI compliance verification are directly triggered by spray window records. The lab_sample has phi_compliance_flag and fsma_sampling_plan_ref. Linking to the spray_window',
    `test_panel_id` BIGINT COMMENT 'Reference to the requested test panel defining the suite of analytical tests to be performed on this sample (e.g., pesticide residue panel, mycotoxin panel, microbiological panel, nutritional panel).',
    `trial_id` BIGINT COMMENT 'Foreign key linking to research.trial. Business justification: Residue and MRL compliance sampling during efficacy trials is a named process: lab samples collected from trial plots must link to the trial for trial residue sampling reports, PHI compliance verifi',
    `analytical_method_code` STRING COMMENT 'Code identifying the approved analytical method used for testing this sample (e.g., AOAC 2007.01 for pesticide residues, EPA Method 8270 for organics, USDA FSIS MLG for microbiology). Ensures regulatory acceptance of test results and supports method validation documentation.',
    `chain_of_custody_number` STRING COMMENT 'Unique identifier for the chain-of-custody document accompanying this sample from collection through laboratory receipt. Provides legal defensibility for test results and supports FSMA traceability and regulatory inspection readiness.',
    `coa_number` STRING COMMENT 'Reference number of the Certificate of Analysis (COA) issued by the laboratory upon completion of testing. The COA is the primary quality document used for product release, customer delivery, and regulatory compliance. Aligns with COA business jargon.',
    `collection_point_description` STRING COMMENT 'Specific description of the exact collection point within the facility or field (e.g., North field block 3, row 12, Bin 7 - top layer, Processing Line 2 - post-wash CCP). Provides granular traceability beyond the collection point type classification.',
    `collection_point_type` STRING COMMENT 'Classification of the physical location or process stage where the sample was collected. Supports field-to-COA traceability and HACCP critical control point mapping. Values: field (in-crop collection), bin (grain storage), processing_line (in-process), receiving_dock (incoming goods), storage (warehouse), transport (in-transit).. Valid values are `field|bin|processing_line|receiving_dock|storage|transport`',
    `collection_timestamp` TIMESTAMP COMMENT 'Date and time when the sample was physically collected from the collection point. The principal real-world event time for this transaction. Critical for chain-of-custody integrity, PHI (Pre-Harvest Interval) compliance verification, and FSMA traceability records.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp when the lab sample record was first created in the data platform. Used for audit trail, data lineage, and Silver layer ingestion tracking.',
    `disposition_action` STRING COMMENT 'Final disposition decision for the physical sample material after testing is complete. Released: sample returned or discarded per protocol after passing; Quarantined: held pending further investigation; Destroyed: sample destroyed per biohazard or regulatory protocol; Returned: sample returned to submitter; Resampled: additional sampling required.. Valid values are `released|quarantined|destroyed|returned|resampled`',
    `disposition_date` DATE COMMENT 'Date on which the final disposition action was executed for the physical sample material. Required for sample retention compliance and laboratory space management.',
    `fsma_sampling_plan_ref` STRING COMMENT 'Reference code or document identifier for the FSMA-compliant sampling plan under which this sample was collected. Supports FDA inspection readiness and FSMA Subpart O environmental monitoring and food safety plan documentation. Aligns with FSMA business jargon.',
    `gfsi_scheme_code` STRING COMMENT 'Identifies the GFSI-benchmarked certification scheme under which this sample was collected or is being used to demonstrate compliance. Supports certification audit readiness for SQF, BRC, IFS, and GLOBALG.A.P. schemes. Aligns with GFSI, SQF, BRC, IFS business jargons.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|FSSC22000|other`',
    `haccp_ccp_flag` BOOLEAN COMMENT 'Indicates whether this sample was collected as part of HACCP (Hazard Analysis and Critical Control Points) critical control point monitoring or verification activities. True requires enhanced documentation and regulatory retention per FSMA Preventive Controls rule. Aligns with HACCP business jargon.',
    `lot_number` STRING COMMENT 'Human-readable batch or lot tracking identifier associated with the sampled material. Denormalized from the commodity lot for direct COA reporting and regulatory submission without requiring a join. Aligns with LOT (Lot Number) business jargon.',
    `mrl_exceedance_flag` BOOLEAN COMMENT 'Indicates whether any test parameter in this sample exceeded the applicable Maximum Residue Limit (MRL) as defined by EPA, Codex Alimentarius, or customer specification. True triggers non-conformance workflow and regulatory notification procedures. Aligns with MRL business jargon.',
    `overall_result` STRING COMMENT 'Consolidated pass/fail determination for the sample based on all test parameters in the requested panel against defined acceptance criteria. Pass: all parameters within specification; Fail: one or more parameters exceeded MRL or acceptance threshold; Inconclusive: results require further review; Pending: testing not yet complete.. Valid values are `pass|fail|inconclusive|pending`',
    `phi_compliance_flag` BOOLEAN COMMENT 'Indicates whether the sample collection date was verified to be after the required Pre-Harvest Interval (PHI) for any applied crop protection products. True confirms PHI compliance at time of sampling. Critical for pesticide residue MRL compliance. Aligns with PHI business jargon.',
    `received_at_lab_timestamp` TIMESTAMP COMMENT 'Date and time when the sample was officially received and logged at the testing laboratory. Used to calculate sample transit time, assess sample integrity, and enforce holding time limits per analytical method requirements.',
    `required_completion_date` DATE COMMENT 'Target date by which laboratory testing and result reporting must be completed. Drives laboratory scheduling, SLA monitoring, and release-hold decisions for production lots awaiting quality clearance.',
    `results_released_timestamp` TIMESTAMP COMMENT 'Date and time when the laboratory officially released the test results and COA. Marks the completion of the testing lifecycle and triggers downstream quality disposition workflows in SAP QM.',
    `sample_condition` STRING COMMENT 'Assessment of the physical condition of the sample upon receipt at the laboratory. Acceptable: sample integrity maintained; Compromised: minor integrity issues noted but testing may proceed with caveats; Rejected: sample integrity failed, testing cannot proceed. Drives chain-of-custody decisions.. Valid values are `acceptable|compromised|rejected`',
    `sample_notes` STRING COMMENT 'Free-text field for additional observations, anomalies, or contextual information recorded at the time of sample collection or receipt. Captures field conditions, equipment calibration notes, or deviations from standard sampling protocol that may affect result interpretation.',
    `sample_number` STRING COMMENT 'Externally-known, human-readable unique identifier assigned to the sample at collection or submission. Used for chain-of-custody documentation, COA traceability, and communication with external laboratories. Follows enterprise sample numbering convention (e.g., LAB-2024-000123).. Valid values are `^LAB-[0-9]{4}-[0-9]{6}$`',
    `sample_quantity` DECIMAL(18,2) COMMENT 'Measured quantity of material collected for the sample (e.g., weight in grams, volume in milliliters). Used to verify adequacy of sample size per analytical method requirements and sampling plan specifications.',
    `sample_quantity_uom` STRING COMMENT 'Unit of measure for the sample quantity field. Standard units include grams (g), kilograms (kg), milliliters (mL), liters (L), milligrams (mg), and ounces (oz). Must align with the unit specified in the analytical method.. Valid values are `g|kg|mL|L|mg|oz`',
    `sample_status` STRING COMMENT 'Current lifecycle status of the laboratory sample from submission through disposition. Drives workflow routing in SAP QM and laboratory tracking systems. Values: submitted (collected and logged), received (confirmed at lab), in_testing (analysis underway), completed (results available), rejected (sample failed receipt criteria), disposed (sample destroyed or returned per protocol).. Valid values are `submitted|received|in_testing|completed|rejected|disposed`',
    `sample_type` STRING COMMENT 'Classification of the physical material collected for laboratory analysis. Determines applicable analytical methods, acceptance criteria, and regulatory reporting requirements. [ENUM-REF-CANDIDATE: grain|soil|water|tissue|feed|environmental_swab|air|product — promote to reference product]',
    `sampling_frequency_code` STRING COMMENT 'Classification of why this sample was collected relative to the sampling plan schedule. Routine: scheduled periodic sampling; Triggered: collected in response to an event or non-conformance; Regulatory: mandated by USDA/FDA/EPA inspection; Verification: HACCP verification sampling; Validation: process or method validation sampling.. Valid values are `routine|triggered|regulatory|verification|validation`',
    `storage_temperature_c` DECIMAL(18,2) COMMENT 'Temperature in degrees Celsius at which the sample was stored during transit and prior to analysis. Critical for maintaining sample integrity for microbiological and chemical analyses. Deviations may invalidate results per ISO/IEC 17025 requirements.',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp of the most recent modification to the lab sample record. Supports incremental data processing in the Databricks Lakehouse Silver layer and audit trail requirements.',
    CONSTRAINT pk_lab_sample PRIMARY KEY(`lab_sample_id`)
) COMMENT 'Laboratory sample submission and tracking records for all quality testing activities. Captures sample collection point (field, bin, processing line, receiving dock), sample type (grain, soil, water, tissue, feed, environmental swab), collection date/time, chain of custody, assigned laboratory, requested test panel, sample condition at receipt, and disposition after testing. Includes testing protocol metadata: sampling plan reference, sampling frequency, approved analytical methods, test parameters, and acceptance criteria. Supports field-to-COA traceability, FSMA sampling plan compliance, and HACCP verification sampling.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`test_result` (
    `test_result_id` BIGINT COMMENT 'Unique system-generated identifier for each individual analytical test result record. Primary key for the test_result data product in the quality domain.',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: Pesticide residue test results must trace to the specific EPA-registered agrochemical product for MRL compliance reporting, regulatory submission, and resistance management tracking. Agriculture labs ',
    `asset_id` BIGINT COMMENT 'Identifier of the laboratory instrument or equipment used to perform the analysis (e.g., HPLC, GC-MS, PCR thermocycler). Supports instrument calibration traceability and ISO/IEC 17025 audit requirements.',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: test_result has coa_eligible (BOOLEAN) indicating the result qualifies for inclusion in a Certificate of Analysis. Adding coa_id FK links the individual test result to the specific COA it was included',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the specific commodity lot (batch) from which the sample was drawn. Enables lot-level traceability for COA generation, regulatory reporting, and potential recall management under FSMA.',
    `employee_id` BIGINT COMMENT 'Reference to the laboratory analyst who performed the test and is responsible for sign-off on the result. Required for COA generation and regulatory audit trails.',
    `facility_id` BIGINT COMMENT 'Reference to the laboratory (internal or third-party accredited) that performed the analytical test. Supports COA generation and regulatory reporting to USDA, FDA, and FSIS.',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Test results for moisture, protein, test weight, and defects are evaluated against specific grading standards. Linking test_result to grading_standard enables automated pass/fail against official USDA',
    `inspection_lot_id` BIGINT COMMENT 'Reference to the SAP QM inspection lot under which this test result was generated. Enables traceability from individual test results back to the originating quality inspection event.',
    `lab_sample_id` BIGINT COMMENT 'Reference to the parent laboratory sample from which this test result was derived. Links the individual test result to its originating sample submission record.',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: test_result stores mrl_threshold as a denormalized numeric column. Linking to mrl_threshold normalizes the regulatory tolerance reference, enabling pass/fail determination against jurisdiction-specifi',
    `nonconformance_id` BIGINT COMMENT 'Reference to the non-conformance record raised as a result of a failed test result. Populated when pass_fail_status is fail, linking the test result to the corrective action workflow in SAP QM.',
    `permit_condition_id` BIGINT COMMENT 'Foreign key linking to compliance.permit_condition. Business justification: Environmental and water quality test results are measured against specific permit conditions (NPDES discharge limits, water quality standards). Compliance officers use test results to determine permit',
    `procurement_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Incoming quality test results (MRL, mycotoxin, germination) must be linked to the specific GRN for lot acceptance/rejection decisions, return claim evidence, and FSMA supplier verification records. te',
    `action_limit` DECIMAL(18,2) COMMENT 'Internal or regulatory action threshold below the MRL that triggers corrective action or investigation before the regulatory limit is breached. Supports HACCP CCP monitoring and FSMA preventive controls.',
    `analyst_signoff_timestamp` TIMESTAMP COMMENT 'The date and time when the laboratory analyst formally reviewed and signed off on the test result. Required for COA issuance and ISO/IEC 17025 quality system compliance.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this test result record was first created in the quality management system. Supports audit trail requirements under FSMA, ISO 22000, and SOX financial reporting controls.',
    `detection_limit` DECIMAL(18,2) COMMENT 'The lowest concentration or quantity of the analyte that can be reliably detected by the test method. Critical for interpreting non-detect results and MRL compliance reporting to FDA and USDA.',
    `dilution_factor` DECIMAL(18,2) COMMENT 'The dilution factor applied to the sample prior to analysis. Used to back-calculate the actual concentration in the original sample matrix and ensure accurate MRL compliance determination.',
    `haccp_ccp_flag` BOOLEAN COMMENT 'Indicates whether this test result is associated with a HACCP Critical Control Point (CCP) monitoring activity. CCP-flagged results require immediate corrective action upon failure and are subject to FSIS and FDA regulatory review.',
    `laboratory_accreditation_number` STRING COMMENT 'The ISO/IEC 17025 or equivalent accreditation number of the laboratory that performed the test. Printed on COAs and required for regulatory submissions to USDA, FDA, and FSIS to validate laboratory competency.',
    `measured_value` DECIMAL(18,2) COMMENT 'The quantitative result of the analytical test as reported by the laboratory instrument or analyst. For qualitative tests (e.g., Salmonella presence/absence), this field is null and qualitative_result is used instead.',
    `parameter_category` STRING COMMENT 'Broad classification of the test parameter type. Supports regulatory reporting segmentation and HACCP critical control point (CCP) categorization. [ENUM-REF-CANDIDATE: mycotoxin|pesticide_residue|microbiological|physical|chemical|nutritional|heavy_metal|sensory — promote to reference product if additional categories are needed]',
    `parameter_name` STRING COMMENT 'Name of the analytical parameter being tested (e.g., aflatoxin B1, glyphosate residue, Salmonella spp., moisture content, pH, Electrical Conductivity (EC), nitrate). Drives COA line-item labeling and MRL threshold comparison.',
    `pass_fail_status` STRING COMMENT 'The compliance determination for this individual test result based on comparison of the measured value against the MRL threshold and action limit. Drives COA issuance, lot release decisions, and regulatory reporting to USDA, FDA, and FSIS.. Valid values are `pass|fail|inconclusive|pending_review`',
    `qualitative_result` STRING COMMENT 'Qualitative outcome for presence/absence or positive/negative tests (e.g., Salmonella not detected, GMO absent). Used when a numeric measured_value is not applicable. Supports FSIS microbiological reporting.. Valid values are `detected|not_detected|present|absent|positive|negative`',
    `quantitation_limit` DECIMAL(18,2) COMMENT 'The lowest concentration at which the analyte can be quantitatively measured with acceptable precision and accuracy. Distinct from LOD; used for MRL compliance determination and COA reporting.',
    `recovery_percent` DECIMAL(18,2) COMMENT 'The percentage recovery of a spiked control sample used to validate the analytical method performance for this test run. Acceptable recovery ranges are defined by AOAC and Codex Alimentarius guidelines (typically 70–120%).',
    `regulatory_program_code` STRING COMMENT 'Code identifying the regulatory monitoring or surveillance program under which this test was conducted (e.g., USDA Pesticide Data Program (PDP), FDA Pesticide Residue Monitoring Program, FSIS National Residue Program (NRP), USDA AMS Microbiological Data Program).',
    `regulatory_submission_required` BOOLEAN COMMENT 'Indicates whether this test result must be reported to a regulatory authority (USDA, FDA, FSIS, EPA, or APHIS). Triggered by failed MRL results, CCP deviations, or mandatory surveillance program requirements.',
    `result_reported_timestamp` TIMESTAMP COMMENT 'The date and time when the test result was formally reported and made available for COA generation and lot release decisions. Used to calculate laboratory turnaround time KPIs.',
    `result_status` STRING COMMENT 'Current workflow status of the test result record within the quality management system. Controls whether the result is eligible for COA inclusion and lot release authorization.. Valid values are `draft|under_review|approved|rejected|cancelled`',
    `result_type` STRING COMMENT 'Indicates whether this result is an original first-run test, a repeat test, a confirmatory test following a suspect result, or a retest after corrective action. Supports regulatory investigation workflows.. Valid values are `original|repeat|confirmatory|retest`',
    `sample_matrix` STRING COMMENT 'The physical material or commodity type being tested (e.g., grain, soil, water, feed, fresh produce, processed food, animal tissue). Determines applicable MRL thresholds and regulatory reporting pathways under USDA, FDA, or FSIS jurisdiction.',
    `test_method_code` STRING COMMENT 'The standardized analytical method reference code used to perform the test (e.g., AOAC 2007.01, ISO 6579, EPA Method 8270D, USDA FSIS MLG 4.10). Required for COA documentation and regulatory method validation compliance.',
    `test_method_name` STRING COMMENT 'Descriptive name of the analytical method used (e.g., AOAC QuEChERS Multi-Residue Pesticide Method, ISO Horizontal Method for Salmonella Detection). Complements the method code for COA readability.',
    `test_notes` STRING COMMENT 'Free-text field for laboratory analyst observations, anomalies, interferences, or qualifications associated with this test result. Supports audit trail documentation and COA footnotes.',
    `test_performed_timestamp` TIMESTAMP COMMENT 'The date and time when the analytical test was physically performed in the laboratory. Distinct from sample receipt and result sign-off timestamps. Critical for FSMA traceability and COA dating.',
    `test_result_number` STRING COMMENT 'Externally-known business identifier for this test result, used on Certificates of Analysis (COA) and regulatory submissions. Typically sourced from SAP QM or the laboratory information management system (LIMS).',
    `uncertainty_value` DECIMAL(18,2) COMMENT 'The expanded measurement uncertainty associated with the test result, expressed in the same unit as the measured value. Required for ISO/IEC 17025 accredited laboratory reporting and MRL compliance boundary decisions.',
    `unit_of_measure` STRING COMMENT 'Unit in which the measured value is expressed (e.g., ppb, ppm, CFU/g, %, mg/kg, pH units, mS/cm for EC). Aligns with Codex Alimentarius and AOAC reporting conventions for regulatory submissions.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this test result record was last modified in the quality management system. Required for data lineage tracking in the Databricks Silver Layer and regulatory audit trail compliance.',
    CONSTRAINT pk_test_result PRIMARY KEY(`test_result_id`)
) COMMENT 'Individual analytical test results associated with a lab sample. Records test parameter name (e.g., aflatoxin, glyphosate residue, Salmonella, moisture content, pH, EC), measured value, unit of measure (ppb, ppm, CFU/g, %), method reference (AOAC, ISO, EPA method), detection limit, MRL threshold, pass/fail determination, and laboratory analyst sign-off. Provides granular traceability for COA generation and regulatory reporting to USDA, FDA, and FSIS.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`haccp_plan` (
    `haccp_plan_id` BIGINT COMMENT 'Unique system-generated identifier for the HACCP plan record. Primary key for this entity. Entity role: MASTER_AGREEMENT — represents a long-running regulatory compliance plan binding a facility/process to documented food safety controls.',
    `commodity_id` BIGINT COMMENT 'Reference to the agricultural commodity or food product category covered by this HACCP plan (e.g., fresh produce, poultry, dairy). Aligns with USDA/FDA commodity classification for regulatory reporting.',
    `facility_id` BIGINT COMMENT 'Reference to the production facility, processing plant, or packing house where this HACCP plan is applied. Links to the facility master record for location, registration, and regulatory context.',
    `food_safety_plan_id` BIGINT COMMENT 'Foreign key linking to compliance.food_safety_plan. Business justification: FSMA Preventive Controls requires HACCP plans to be incorporated into or aligned with the facilitys Food Safety Plan. Quality and compliance officers must link the HACCP plan to the FSMA food safety ',
    `livestock_product_id` BIGINT COMMENT 'Foreign key linking to product.livestock_product. Business justification: FSIS-regulated livestock operations require HACCP plans specific to each livestock product (species, cut, processing method). Linking haccp_plan to livestock_product enables FSIS establishment complia',
    `employee_id` BIGINT COMMENT 'Reference to the qualified individual designated as the HACCP team leader responsible for plan development, maintenance, and regulatory compliance. Corresponds to Codex Alimentarius Step 1 (assemble HACCP team).',
    `processed_good_id` BIGINT COMMENT 'Foreign key linking to product.processed_good. Business justification: HACCP plans under FSMA Preventive Controls are written for specific processed food products. Linking haccp_plan to processed_good (which has haccp_plan_reference as text) enables bidirectional FSMA co',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: ISCC, Rainforest Alliance, and organic certification standards require documented HACCP or food safety plans as prerequisite programs. Linking haccp_plan to sustainability_certification enables certif',
    `approval_date` DATE COMMENT 'Date on which the current version of the HACCP plan was formally approved by authorized management. Distinct from effective_date; approval may precede implementation.',
    `biological_hazards_identified` BOOLEAN COMMENT 'Indicates whether biological hazards (e.g., Salmonella, E. coli O157:H7, Listeria monocytogenes) were identified as significant hazards requiring a Critical Control Point (CCP) in this HACCP plan.',
    `ccp_count` STRING COMMENT 'Total number of Critical Control Points (CCPs) identified and documented within this HACCP plan. Used for plan completeness validation and audit readiness checks.',
    `ccp_description` STRING COMMENT 'Narrative description of the CCP process step where control is applied (e.g., Pasteurization heat treatment, Metal detection at packaging line exit, Chlorine wash for fresh produce).',
    `ccp_number` STRING COMMENT 'Unique identifier for a specific Critical Control Point within the HACCP plan (e.g., CCP-1B for biological, CCP-2C for chemical, CCP-3P for physical). Used to cross-reference monitoring logs and corrective action records.. Valid values are `^CCP-[0-9]{1,3}[BCPbcp]?$`',
    `chemical_hazards_identified` BOOLEAN COMMENT 'Indicates whether chemical hazards (e.g., pesticide residues exceeding MRL, allergens, mycotoxins, heavy metals, cleaning chemical residues) were identified as significant hazards in this HACCP plan.',
    `corrective_action_procedure` STRING COMMENT 'Documented procedure to be followed when a deviation from the critical limit is detected at the CCP, including product disposition, process correction, and root cause investigation steps. Corresponds to Codex Alimentarius Principle 5.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this HACCP plan record was first created in the system. Supports audit trail, data lineage, and regulatory record-keeping requirements.',
    `critical_limit_description` STRING COMMENT 'Documented critical limit(s) for each CCP that distinguish safe from unsafe product (e.g., Internal temperature ≥ 72°C for ≥ 15 seconds, Chlorine concentration 50–200 ppm, Metal detector sensitivity: 1.5mm ferrous). Corresponds to Codex Alimentarius Principle 3.',
    `deviation_flag` BOOLEAN COMMENT 'Indicates whether any active deviation from a critical limit has been recorded against this HACCP plan in the current monitoring period. True signals that a corrective action is open or pending closure.',
    `effective_date` DATE COMMENT 'Date on which this version of the HACCP plan became operationally effective and was implemented in production. Marks the start of the plans binding period for compliance purposes.',
    `expiry_date` DATE COMMENT 'Date on which this HACCP plan version expires or is scheduled for mandatory reassessment review. Nullable for open-ended plans; populated when a defined review cycle is mandated by the regulatory framework or certification body.',
    `fsma_preventive_controls_applicable` BOOLEAN COMMENT 'Indicates whether this HACCP plan is subject to the FDA Food Safety Modernization Act (FSMA) Preventive Controls for Human Food rule (21 CFR Part 117). False may apply to exempt facilities or animal food operations governed by a separate rule.',
    `gfsi_scheme` STRING COMMENT 'GFSI-benchmarked certification scheme under which this HACCP plan is audited (Safe Quality Food (SQF), British Retail Consortium (BRC), International Featured Standards (IFS), FSSC 22000, or GLOBALG.A.P.). Drives audit scope and documentation requirements.. Valid values are `SQF|BRC|IFS|FSSC_22000|GLOBALG.A.P.|none`',
    `hazard_analysis_summary` STRING COMMENT 'Narrative summary of the hazard analysis conducted for this plan, documenting the methodology used to identify and evaluate biological, chemical, and physical hazards at each process step. Corresponds to Codex Alimentarius Principle 1.',
    `intended_use` STRING COMMENT 'Documented intended use and consumer population for the product covered by this plan, including whether the product is intended for vulnerable populations (e.g., infants, immunocompromised). Informs hazard severity assessment.',
    `last_review_date` DATE COMMENT 'Date of the most recent formal reassessment or revalidation of the HACCP plan, triggered by process changes, new hazard information, regulatory updates, or scheduled periodic review. Required by FDA FSMA and GFSI schemes.',
    `monitoring_frequency` STRING COMMENT 'Frequency at which the monitoring parameter is measured at the CCP (e.g., continuous, every batch, hourly, per shift). Defined in the HACCP plan and enforced during production operations. [ENUM-REF-CANDIDATE: continuous|every_batch|hourly|every_2_hours|daily|per_shift|other — 7 candidates stripped; promote to reference product]',
    `monitoring_method` STRING COMMENT 'Description of the procedure, instrument, or technique used to monitor the CCP parameter (e.g., Calibrated digital thermometer, Inline pH meter, Metal detector test piece challenge). Supports equipment calibration traceability.',
    `monitoring_parameter` STRING COMMENT 'The physical or chemical parameter measured at the CCP to verify the critical limit is being met (e.g., temperature in °C, pH, chlorine concentration in ppm, metal detector sensitivity in mm). Corresponds to Codex Alimentarius Principle 4. [ENUM-REF-CANDIDATE: temperature|pH|chlorine_concentration|metal_detector_sensitivity|water_activity|time|pressure|flow_rate|turbidity|conductivity|other — promote to reference product]',
    `next_review_date` DATE COMMENT 'Date by which the next formal reassessment of the HACCP plan must be completed. Used for compliance calendar management and audit readiness tracking.',
    `open_corrective_actions` STRING COMMENT 'Count of corrective action records currently open and unresolved against this HACCP plan. Used for compliance dashboard monitoring and audit readiness assessment. Zero indicates full compliance.',
    `physical_hazards_identified` BOOLEAN COMMENT 'Indicates whether physical hazards (e.g., metal fragments, glass, bone, hard plastic, stones) were identified as significant hazards requiring a CCP such as metal detection or X-ray inspection in this HACCP plan.',
    `plan_name` STRING COMMENT 'Descriptive human-readable name of the HACCP plan, typically referencing the commodity, process line, or facility scope (e.g., Fresh-Cut Leafy Greens Processing — Facility A).',
    `plan_number` STRING COMMENT 'Externally-known unique alphanumeric identifier for the HACCP plan, used in regulatory submissions, audit documentation, and cross-system references (e.g., SAP QM inspection lot linkage). Format: HACCP-{FACILITY_CODE}-{YEAR}-{SEQ}.. Valid values are `^HACCP-[A-Z0-9]{3,10}-[0-9]{4}-[0-9]{3}$`',
    `plan_scope` STRING COMMENT 'Defines the operational scope of the HACCP plan — whether it covers an entire facility, a specific process line, a commodity category, or a specific finished product. Determines applicability during audits.. Valid values are `facility_wide|process_line|commodity_specific|product_specific|seasonal`',
    `plan_status` STRING COMMENT 'Current lifecycle state of the HACCP plan. active indicates the plan is in operational use; under_review indicates a scheduled reassessment is in progress; suspended indicates temporary halt pending corrective action; superseded indicates replaced by a newer version.. Valid values are `draft|active|under_review|suspended|superseded|archived`',
    `plan_version` STRING COMMENT 'Version number of the HACCP plan document, incremented upon each formal review or revision cycle. Supports document control and audit trail requirements (e.g., 1.0, 2.3).. Valid values are `^[0-9]+.[0-9]+$`',
    `prerequisite_programs` STRING COMMENT 'List of prerequisite programs (PRPs) supporting this HACCP plan, such as Good Manufacturing Practices (GMP), sanitation standard operating procedures (SSOPs), pest control, and allergen management programs. PRPs are foundational controls that underpin the HACCP system.',
    `process_description` STRING COMMENT 'Narrative description of the production or processing scope covered by this HACCP plan, including process flow steps from raw material receipt through finished product dispatch. Required by Codex Alimentarius Step 4 (process flow diagram description).',
    `recordkeeping_requirements` STRING COMMENT 'Description of the records that must be maintained to document HACCP plan implementation, including monitoring logs, corrective action records, verification records, and retention periods. Corresponds to Codex Alimentarius Principle 7.',
    `regulatory_framework` STRING COMMENT 'Primary regulatory or certification framework under which this HACCP plan was developed and is maintained (e.g., FDA FSMA Preventive Controls, FSIS HACCP, GFSI scheme such as SQF or BRC). Determines audit requirements and record retention obligations. [ENUM-REF-CANDIDATE: FDA_FSMA|FSIS_HACCP|USDA_NOP|GLOBALG.A.P.|SQF|BRC|IFS|ISO_22000|Codex_Alimentarius|EU_852_2004|other — promote to reference product]. Valid values are `FDA_FSMA|FSIS_HACCP|USDA_NOP|GLOBALG.A.P.|SQF|BRC|IFS|ISO_22000|Codex_Alimentarius|other`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this HACCP plan record in the system. Used for change tracking, version control, and data synchronization with SAP QM module.',
    `verification_procedure` STRING COMMENT 'Documented activities used to confirm the HACCP plan is functioning effectively, including calibration schedules, record review, periodic product testing, and internal audits. Corresponds to Codex Alimentarius Principle 6.',
    CONSTRAINT pk_haccp_plan PRIMARY KEY(`haccp_plan_id`)
) COMMENT 'HACCP (Hazard Analysis and Critical Control Points) plan master records with embedded CCP monitoring logs for each production process, commodity, or facility. Plan-level: defines process scope, hazard analysis summary, identified biological/chemical/physical hazards, critical control points (CCPs), critical limits, monitoring procedures, corrective action procedures, verification activities, and record-keeping requirements. CCP monitoring log detail: captures real-time or periodic measurements at each CCP including monitoring parameter (temperature, pH, chlorine concentration, metal detector sensitivity), measured value, critical limit, monitoring frequency, operator identity, timestamp, deviation flag, and immediate corrective action taken. Provides both the plan framework and continuous compliance evidence required by FDA FSMA Preventive Controls rule and GFSI scheme auditors (SQF, BRC, IFS).';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`quality_certification` (
    `quality_certification_id` BIGINT COMMENT 'Unique surrogate identifier for each quality and food safety certification record held by the enterprise. Primary key for the quality_certification data product.',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Annual certification fees (organic, GFSI, GlobalG.A.P.) are charged to cost centers. Certification cost tracking for management accounting and budget planning in agriculture requires this link to allo',
    `document_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_document. Business justification: Quality certifications (organic, GFSI, GlobalG.A.P.) are managed as compliance documents for renewal tracking and regulatory submission. Compliance managers maintain the certificate as a compliance do',
    `facility_id` BIGINT COMMENT 'Reference to the internal facility or site master record covered by this certification. Links the certificate to the enterprises facility hierarchy for operational and regulatory reporting.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: Organic certificates, GlobalG.A.P. certificates, and GAP certifications in agriculture are issued to farm operations. Linking quality_certification to farm_unit enables direct lookup of which certific',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Certification fees and renewal costs are posted to GL accounts as licensing/certification expense. Financial reporting and cost-of-quality analysis require certification costs mapped to a GL account f',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: Facility-level quality certifications for organic operations (USDA NOP) must reference the product-level organic certificate. This link enables NOP compliance verification, certificate renewal coordin',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: Dual certification programs (GlobalG.A.P.+GRASP, GFSI+ISCC, organic+Rainforest Alliance) are standard in agriculture. Quality certification records must reference the co-assessed sustainability certif',
    `accreditation_body` STRING COMMENT 'The national or international accreditation body that accredits the certification body (e.g., ANAB - ANSI National Accreditation Board, UKAS - United Kingdom Accreditation Service, DAkkS). Validates the legitimacy of the certification body and is required for GFSI scheme recognition.',
    `audit_type` STRING COMMENT 'The type of audit that resulted in or is associated with this certification record: initial (first-time certification), recertification (renewal at end of cycle), surveillance (periodic interim audit), unannounced (surprise audit required by some GFSI schemes), or extension (scope extension audit).. Valid values are `initial|recertification|surveillance|unannounced|extension`',
    `body` STRING COMMENT 'The name of the accredited third-party certification body or registrar that issued the certificate (e.g., NSF International, SGS, Bureau Veritas, DNV, Intertek). Required for regulatory reporting to USDA, FDA, and FSIS and for GFSI scheme compliance.',
    `certificate_document_ref` STRING COMMENT 'Reference path or document management system identifier pointing to the scanned or digital copy of the issued certificate (e.g., SharePoint URL, SAP DMS document number). Enables direct access to the certificate document for audits and customer requests.',
    `certificate_number` STRING COMMENT 'The externally-issued, unique certificate number assigned by the certification body. Used for regulatory submissions, audit trails, and customer-facing documentation (e.g., COA, supplier declarations). Aligns with SAP S/4HANA QM module certificate tracking.',
    `certification_status` STRING COMMENT 'Current lifecycle status of the certification. Active: certificate is valid and in good standing. Suspended: temporarily halted by the certification body pending corrective action. Withdrawn: permanently revoked. Expired: past the expiry date without renewal. Pending: initial application or renewal in progress. Under_review: surveillance audit or non-conformance review in progress. Drives certification readiness dashboards and renewal workflows.. Valid values are `active|suspended|withdrawn|expired|pending|under_review`',
    `certification_type` STRING COMMENT 'High-level classification of the certification by its primary purpose: food_safety (SQF, BRC, IFS, HACCP-based), environmental (ISO 14001, ISCC), organic (USDA NOP), sustainability (ISCC, Fair Trade), social (Fair Trade), or quality_management (ISO 22000). Supports portfolio-level reporting and gap analysis.. Valid values are `food_safety|environmental|organic|sustainability|social|quality_management`',
    `corrective_action_due_date` DATE COMMENT 'The deadline by which all corrective actions arising from audit non-conformances must be submitted to the certification body. Null if no open non-conformances exist. Drives corrective action workflow and escalation alerts.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the country where the certified facility or operation is located (e.g., USA, BRA, DEU). Required for COOL (Country of Origin Labeling) compliance and international regulatory reporting.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this certification record was first created in the system. Supports audit trail, data lineage, and FSMA record-keeping requirements.',
    `expiry_date` DATE COMMENT 'The date on which the certificate expires and must be renewed to maintain certified status. Null for open-ended certifications. Triggers renewal workflow alerts and drives certification readiness dashboards.',
    `gfsi_scheme_flag` BOOLEAN COMMENT 'Indicates whether this certification is recognized under the Global Food Safety Initiative (GFSI) benchmarking framework (True) or is a non-GFSI scheme (False). GFSI-recognized schemes include SQF, BRC, IFS, FSSC 22000, and GLOBALG.A.P. Critical for customer and retailer compliance requirements.',
    `globalg_ap_producer_number` STRING COMMENT 'The unique GLOBALG.A.P. producer or certificate number assigned by the GLOBALG.A.P. secretariat and published in the GLOBALG.A.P. database. Required for GLOBALG.A.P. certification verification by buyers and retailers.',
    `grade_or_level` STRING COMMENT 'The grade, level, or rating awarded by the certification body upon successful audit (e.g., SQF Level 2, SQF Level 3, BRC Grade AA/A/B/C/D, IFS Higher Level/Foundation Level). Null for schemes that do not use graded outcomes. Used for benchmarking and customer qualification.',
    `initial_certification_date` DATE COMMENT 'The date on which the facility or operation first achieved certification under this scheme, regardless of subsequent renewals. Used to calculate certification tenure and demonstrate long-standing compliance to customers and regulators.',
    `iscc_certificate_number` STRING COMMENT 'The unique certificate number issued under the International Sustainability and Carbon Certification (ISCC) scheme for bioenergy and biomass sustainability compliance. Null for non-ISCC certifications.',
    `issue_date` DATE COMMENT 'The date on which the certification body formally issued the certificate. Marks the start of the certification validity period. Used for compliance tracking and regulatory reporting to USDA, FDA, and FSIS.',
    `multi_site_flag` BOOLEAN COMMENT 'Indicates whether this certificate covers multiple sites or facilities under a single certificate number (True) or a single site (False). Multi-site certifications are common for GLOBALG.A.P. Option 2 and BRC multi-site schemes.',
    `next_audit_date` DATE COMMENT 'The planned date for the next certification or surveillance audit as agreed with the certification body. Drives the surveillance audit schedule and renewal workflow alerts in the certification readiness dashboard.',
    `nonconformance_count_major` STRING COMMENT 'The number of major non-conformances identified during the most recent certification audit. Major non-conformances require corrective action within a defined timeframe and may result in certification suspension if unresolved. Tracked per SAP S/4HANA QM module non-conformance records.',
    `nonconformance_count_minor` STRING COMMENT 'The number of minor non-conformances identified during the most recent certification audit. Minor non-conformances require corrective action but do not immediately threaten certification status. Tracked per SAP S/4HANA QM module.',
    `notes` STRING COMMENT 'Free-text field for additional remarks, conditions, or qualifications associated with the certification (e.g., scope limitations, special conditions imposed by the certification body, internal observations). Supports operational context for quality managers.',
    `product_category_scope` STRING COMMENT 'The product category or commodity type covered by the certification scope as defined by the scheme (e.g., GLOBALG.A.P. crop category: Fruit and Vegetables; BRC product category: Fresh Produce; SQF food sector category). Supports product-level compliance mapping.',
    `renewal_reminder_days` STRING COMMENT 'The number of calendar days before the expiry date at which automated renewal reminder notifications should be triggered. Configurable per scheme to align with certification body lead times and internal preparation requirements.',
    `responsible_manager` STRING COMMENT 'Name or employee identifier of the internal quality manager or food safety coordinator responsible for maintaining this certification and managing the renewal process. Supports accountability tracking and escalation workflows.',
    `sap_qm_inspection_lot` STRING COMMENT 'The SAP S/4HANA QM module inspection lot number associated with the certification audit or quality inspection event. Enables traceability between the certification record and the source system inspection record for audit and compliance purposes.',
    `scheme_name` STRING COMMENT 'The name of the food safety or quality certification scheme under which the certificate was issued (e.g., Safe Quality Food (SQF), British Retail Consortium (BRC), International Featured Standards (IFS), GLOBALG.A.P., ISO 22000, USDA Organic/National Organic Program (NOP), International Sustainability and Carbon Certification (ISCC), Fair Trade). Drives certification readiness dashboards and renewal workflows.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|ISO 22000|ISO 14001|USDA Organic|ISCC|Fair Trade|FSMA`',
    `scheme_version` STRING COMMENT 'The edition or version number of the certification scheme standard under which the audit was conducted (e.g., SQF Edition 9, BRC Issue 9, IFS Food Version 8). Critical for tracking standard upgrades and ensuring compliance with the current scheme revision.',
    `scope_description` STRING COMMENT 'Narrative description of the products, processes, activities, or operations covered by the certificate as defined by the certification body (e.g., Production and packing of fresh vegetables, Manufacture of animal feed). Directly reflects the scope statement printed on the certificate.',
    `suspension_date` DATE COMMENT 'The date on which the certification body formally suspended the certificate, if applicable. Null for active or non-suspended certifications. Required for regulatory reporting and customer notification obligations.',
    `suspension_reason` STRING COMMENT 'Narrative description of the reason for certification suspension as communicated by the certification body (e.g., unresolved major non-conformances, product recall, failure to submit corrective actions). Null if not suspended.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this certification record was last modified. Supports audit trail, change tracking, and FSMA record-keeping requirements.',
    `usda_organic_op_number` STRING COMMENT 'The USDA National Organic Program (NOP) operation number assigned to the certified organic operation. Required for USDA organic labeling compliance and traceability under the National Organic Program regulations.',
    `withdrawal_date` DATE COMMENT 'The date on which the certificate was permanently withdrawn or voluntarily surrendered. Null for active certifications. Required for regulatory reporting and audit trail completeness.',
    CONSTRAINT pk_quality_certification PRIMARY KEY(`quality_certification_id`)
) COMMENT 'SSOT for all quality and food safety certifications held by the enterprise, including GFSI scheme certifications (SQF, BRC, IFS), GLOBALG.A.P., USDA Organic (NOP), ISCC, Fair Trade, and ISO 22000/14001. Captures certification body, scheme name, scope of certification, certificate number, issue date, expiry date, surveillance audit schedule, current status (active, suspended, withdrawn), and facility or operation covered. Drives certification readiness dashboards and renewal workflows.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`quality_audit` (
    `quality_audit_id` BIGINT COMMENT 'Unique system-generated identifier for each formal quality or food safety audit record. Primary key for the audit data product.',
    `compliance_audit_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_audit. Business justification: A quality audit (GFSI, GlobalG.A.P.) is formally registered as a compliance audit event for regulatory reporting. Quality managers and compliance officers must link internal audit records to complianc',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Third-party GFSI and GlobalG.A.P. audits incur certification body fees and travel costs charged to cost centers. Certification cost tracking and cost-of-quality management accounting in agriculture re',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Customer-mandated audits (GFSI, GlobalG.A.P., SQF) are a standard agriculture commercial requirement — buyers require certified suppliers. Linking audit to the requesting customer account enables cust',
    `employee_id` BIGINT COMMENT 'Reference to the lead auditor or auditing body representative responsible for conducting this audit.',
    `facility_id` BIGINT COMMENT 'Reference to the facility, farm, processing plant, or operational site that was the subject of this audit.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: USDA Organic, GlobalG.A.P., and GFSI scheme audits are issued to farm operations. Linking audit to farm_unit enables the farm-level audit history required for certification renewal, buyer qualificatio',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: GAP audits and organic certification audits are conducted at the field level. Linking audit to field enables field-level audit history and traceability of which fields are GAP-certified — a named requ',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Audit fees (certification body, third-party auditor) are posted to GL accounts as certification/compliance expense. Financial period-close and cost-of-quality P&L reporting require audit costs mapped ',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_obligation. Business justification: Quality audits (annual GFSI, GlobalG.A.P.) fulfill specific compliance obligations mandated by regulation or certification scheme. Linking audit to compliance_obligation enables compliance managers to',
    `previous_audit_quality_audit_id` BIGINT COMMENT 'Reference to the immediately preceding audit record for the same facility and standard, enabling trend analysis and certification history tracking.',
    `regulatory_agency_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_agency. Business justification: quality.audit has a plain-text regulatory_body column. Normalizing to compliance.regulatory_agency enables agency-level audit reporting and enforcement tracking. Quality audits conducted under USDA, F',
    `trial_site_id` BIGINT COMMENT 'Foreign key linking to the specific trial site included in scope for this audit.',
    `workforce_certification_id` BIGINT COMMENT 'Foreign key linking to the specific worker certification or license that was reviewed during this audit.',
    `actual_end_date` DATE COMMENT 'The actual calendar date on which the audit concluded, including closing meeting. Used to calculate audit duration and track completion.',
    `actual_start_date` DATE COMMENT 'The actual calendar date on which the audit commenced on-site or remotely. May differ from scheduled_date due to rescheduling.',
    `announced` BOOLEAN COMMENT 'Indicates whether the auditee was given advance notice of the audit (True = announced, False = unannounced). Unannounced audits are required by certain standards (e.g., BRC unannounced option) and carry higher credibility with retail customers.',
    `audit_method` STRING COMMENT 'The method by which the audit was conducted: on_site (physical presence at the facility), remote (conducted via video/document sharing), hybrid (combination of on-site and remote), or document_review (desk-based review only).. Valid values are `on_site|remote|hybrid|document_review`',
    `audit_number` STRING COMMENT 'Externally-known, human-readable unique reference number assigned to this audit, used in correspondence, reports, and regulatory submissions. Follows the format AUD-YYYY-NNNNNN.. Valid values are `^AUD-[0-9]{4}-[0-9]{6}$`',
    `audit_scope` STRING COMMENT 'Narrative description of the operations, processes, product categories, or geographic areas covered by this audit (e.g., Fresh produce packing and cold storage operations, Grain receiving and storage — Facility A).',
    `audit_status` STRING COMMENT 'Current lifecycle state of the audit record, tracking progression from scheduling through completion or cancellation.. Valid values are `scheduled|in_progress|completed|cancelled|on_hold`',
    `audit_type` STRING COMMENT 'Classification of the audit by party relationship: internal (first-party, conducted by own staff), second_party (customer or buyer-initiated), third_party (independent certification body), regulatory (government agency), or surveillance (periodic check between full certification cycles).. Valid values are `internal|second_party|third_party|regulatory|surveillance`',
    `auditing_body` STRING COMMENT 'Name of the certification body, regulatory agency, or organization that conducted or commissioned the audit (e.g., NSF International, SGS, Bureau Veritas, USDA AMS, FDA).',
    `auditor_notes` STRING COMMENT 'Free-text notes recorded by the auditor regarding this specific credential during this specific audit. May include observations about renewal status, scope limitations, or corrective action recommendations specific to this credential review.',
    `certificate_expiry_date` DATE COMMENT 'The date on which the current certificate expires and recertification is required. Critical for audit program scheduling and maintaining uninterrupted certification status.',
    `certificate_issue_date` DATE COMMENT 'The date on which the certification body formally issued the certificate following a successful audit. Marks the start of the certification validity period.',
    `certificate_number` STRING COMMENT 'The unique certificate number issued by the certification body upon successful audit completion. Used for regulatory submissions, customer verification, and GFSI database registration.',
    `certification_outcome` STRING COMMENT 'The formal certification decision resulting from the audit: certified (new certification granted), recertified (existing certification renewed), conditional (certification granted with conditions), suspended (certification temporarily withdrawn), withdrawn (certification permanently revoked), or not_certified (audit failed).. Valid values are `certified|recertified|conditional|suspended|withdrawn|not_certified`',
    `certification_standard` STRING COMMENT 'The formal quality or food safety standard against which this audit was conducted (e.g., SQF, BRC, IFS, GLOBALG.A.P., USDA Organic, ISO 22000, HACCP, GAP). [ENUM-REF-CANDIDATE: SQF|BRC|IFS|GLOBALG.A.P.|USDA_Organic|ISO_22000|HACCP|GAP|GMP|FSMA — promote to reference product]',
    `corrective_action_closed_date` DATE COMMENT 'The date on which all corrective actions from this audit were formally accepted and closed by the auditing body or internal quality team. Null if corrective actions are still open.',
    `corrective_action_due_date` DATE COMMENT 'The deadline by which all required corrective actions from this audit must be submitted to the auditing body or documented as completed. Null if no corrective actions are required.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether one or more corrective actions are required as a result of this audit. True when any major or minor non-conformances were identified that mandate a formal corrective action response.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this audit record was first created in the system. Used for data lineage, audit trail, and Silver layer ingestion tracking.',
    `duration_days` STRING COMMENT 'Total number of calendar days the audit spanned from actual start to actual end. Used for audit program benchmarking and resource planning.',
    `finding_if_expired` STRING COMMENT 'The formal audit finding recorded if the credential was expired, lapsed, or otherwise non-compliant at the time of the audit review. Populated only when the credential failed verification; null if the credential was current and valid.',
    `fsma_rule` STRING COMMENT 'The specific FSMA rule or subpart applicable to this audit, if the audit is FSMA-related (e.g., Produce Safety Rule, Preventive Controls for Human Food, Foreign Supplier Verification Program). Null for non-FSMA audits.',
    `gap_certified` BOOLEAN COMMENT 'Indicates whether this audit resulted in or maintained a Good Agricultural Practices (GAP) certification. Relevant for USDA GAP/GHP audits and GLOBALG.A.P. assessments.',
    `grade` STRING COMMENT 'Letter grade or categorical rating assigned as the audit outcome per the applicable standard (e.g., BRC AA/A/B/C/D, SQF Excellent/Good/Satisfactory/Unsatisfactory). Null if the standard uses numeric score only. [ENUM-REF-CANDIDATE: AA|A|B|C|D|Excellent|Good|Satisfactory|Unsatisfactory — 9 candidates stripped; promote to reference product]',
    `lead_auditor_credential` STRING COMMENT 'Professional certification or credential held by the lead auditor (e.g., SQF Practitioner, PCQI, REHS, ISO 22000 Lead Auditor). Validates auditor competency for the standard being assessed.',
    `lead_auditor_name` STRING COMMENT 'Full name of the lead auditor who conducted the audit. Captured for traceability and credential verification purposes.',
    `major_nonconformance_count` STRING COMMENT 'Total number of major non-conformances (critical findings) identified during the audit. Major non-conformances typically jeopardize certification and require immediate corrective action.',
    `minor_nonconformance_count` STRING COMMENT 'Total number of minor non-conformances identified during the audit. Minor non-conformances require corrective action within a defined timeframe but do not immediately jeopardize certification.',
    `next_audit_due_date` DATE COMMENT 'The date by which the next audit (recertification or surveillance) must be completed to maintain continuous certification status. Derived from certificate expiry and standard-specific surveillance requirements.',
    `notes` STRING COMMENT 'Free-text field for additional context, special conditions, auditor remarks, or internal quality team commentary not captured in structured fields.',
    `observation_count` STRING COMMENT 'Total number of observations or opportunities for improvement noted during the audit. Observations are not non-conformances but indicate areas where practices could be strengthened.',
    `overall_score` DECIMAL(18,2) COMMENT 'Numeric score or percentage achieved in the audit against the applicable standard. Scoring methodology varies by standard (e.g., SQF uses percentage, BRC uses weighted scoring). Null if the standard uses grade-only outcomes.',
    `report_issued_date` DATE COMMENT 'The date on which the formal audit report was issued by the auditing body to the auditee. Marks the start of the corrective action response window.',
    `report_number` STRING COMMENT 'The unique reference number of the formal audit report document issued by the auditing body. Used for document management, regulatory submissions, and customer sharing.',
    `scheduled_date` DATE COMMENT 'The planned calendar date on which the audit was originally scheduled to begin. Used for audit program planning and resource coordination.',
    `site_audit_scope` STRING COMMENT 'Narrative description of the operations, processes, or product categories audited at this specific trial site within the broader audit engagement. May differ from the overall audit scope when a multi-site audit covers different activities at each site.',
    `site_certification_outcome` STRING COMMENT 'The formal certification decision for this specific trial site resulting from the audit. In multi-site campaigns, individual sites may receive different outcomes (e.g., one site certified, another conditionally certified). Cannot reside on audit alone as it varies per site.',
    `standard_version` STRING COMMENT 'The specific version or edition of the certification standard used for this audit (e.g., SQF Edition 9, BRC Issue 9, IFS Food Version 8). Critical for tracking compliance against evolving standard requirements.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this audit record was last modified. Used for change tracking, data synchronization with SAP S/4HANA QM module, and Silver layer delta processing.',
    `verification_date` DATE COMMENT 'The specific date on which the auditor verified this credential during the audit. Distinct from workforce_certification.verification_date, which records the general HR verification date independent of any audit.',
    `verified_flag` BOOLEAN COMMENT 'Indicates whether the certification or license was confirmed as current, valid, and compliant at the time of this audit review. True means the auditor verified the credential was in good standing during the audit; false indicates it could not be verified or was found non-compliant.',
    CONSTRAINT pk_quality_audit PRIMARY KEY(`quality_audit_id`)
) COMMENT 'Master record for all formal quality and food safety audits including internal audits, second-party customer audits, and third-party certification audits (SQF, BRC, IFS, GLOBALG.A.P., USDA Organic). Captures audit type, auditing body or auditor name, audit scope, facility or operation audited, scheduled and actual audit dates, audit standard and version, overall grade or score, and certification outcome. Distinct from operational inspections — audits are formal system-level assessments against a defined standard.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`facility_monitoring` (
    `facility_monitoring_id` BIGINT COMMENT 'Primary key for facility_monitoring',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: Facility pest control applications use EPA-registered agrochemical products. Linking facility_monitoring to agrochemical_product enables restricted-use pesticide recordkeeping (required by EPA), PHI c',
    `corrective_action_id` BIGINT COMMENT 'Reference to the corrective action record created in response to a monitoring failure or threshold exceedance. Links to the non-conformance and corrective action management system (SAP S/4HANA QM).',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Pest control services and sanitation programs incur costs (pest control contracts, cleaning agents, ATP testing) charged to cost centers. GMP compliance cost tracking and facility operating cost repor',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Pest monitoring and sanitation events in agriculture are performed by designated crews. Tracking which crew executed a monitoring event is required for GAP compliance recordkeeping and labor accountab',
    `facility_id` BIGINT COMMENT 'Reference to the facility, field, storage unit, processing area, or equipment location where the monitoring event occurred. Links to the facility master record.',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Frost events trigger facility monitoring activities — checking stored produce for freeze damage, post-thaw sanitation verification, and pest activity changes after temperature swings. Linking facility',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: Facility monitoring (IPM, sanitation, hygiene verification) supports HACCP prerequisite programs. This FK links facility monitoring activities to the HACCP plan they support. No columns to remove as f',
    `inspection_id` BIGINT COMMENT 'Reference to the formal inspection record in the quality.inspection product that this monitoring event is associated with or contributes evidence to (e.g., GLOBALG.A.P. audit, GFSI certification audit).',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: facility_monitoring records pest scouting, sanitation execution, and hygiene verification events. When action_threshold_exceeded=true or microbial_pass_fail indicates failure, a nonconformance should ',
    `pen_location_id` BIGINT COMMENT 'Foreign key linking to livestock.pen_location. Business justification: Pen-level sanitation, pest monitoring, and biosecurity checks are conducted at specific pen locations within livestock facilities. Linking facility_monitoring to pen_location enables pen-specific sani',
    `permit_condition_id` BIGINT COMMENT 'Foreign key linking to compliance.permit_condition. Business justification: Facility pest and sanitation monitoring results are required by permit conditions (CAFO sanitation standards, water quality permit conditions). Linking monitoring records to permit conditions enables ',
    `employee_id` BIGINT COMMENT 'Reference to the workforce record of the individual who performed the scouting observation or sanitation operation. Supports accountability and training compliance tracking.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Pest monitoring and sanitation events occur at specific storage locations (grain bins, warehouses). Linking to storage_location enables pest pressure mapping against inventory locations — required for',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: IPM programs in ag operations explicitly correlate pest population counts and trap results with weather observations (temperature, humidity, precipitation). This link supports pest pressure analysis r',
    `worker_protection_record_id` BIGINT COMMENT 'Foreign key linking to compliance.worker_protection_record. Business justification: Facility sanitation monitoring (cleaning agent concentrations, REI compliance verification, decontamination site checks) is directly referenced in EPA Worker Protection Standard records. Linking enabl',
    `action_threshold_exceeded` BOOLEAN COMMENT 'Indicates whether the observed pest population count has exceeded the defined action threshold, triggering a required IPM intervention or pesticide application. True = threshold exceeded; False = within acceptable limits.',
    `atp_pass_fail` STRING COMMENT 'Pass/fail determination for the ATP swab test based on the facilitys defined RLU threshold. Drives corrective action requirements and GFSI audit evidence documentation.. Valid values are `pass|fail|not_tested`',
    `atp_test_result_rlu` DECIMAL(18,2) COMMENT 'Result of the ATP bioluminescence swab test expressed in Relative Light Units (RLU). Lower values indicate cleaner surfaces. Compared against the facilitys pass/fail threshold to validate sanitation effectiveness per FSMA preventive controls.',
    `cleaning_agent_concentration_ppm` DECIMAL(18,2) COMMENT 'Concentration of the cleaning or sanitizing agent applied, expressed in parts per million (PPM). Must fall within the EPA-registered or manufacturer-specified range for food-contact surface sanitation.',
    `contact_time_minutes` DECIMAL(18,2) COMMENT 'Actual duration in minutes that the cleaning or sanitizing agent remained in contact with the surface being treated. Compared against the required minimum contact time specified in the SOP (Standard Operating Procedure) for efficacy validation.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether a corrective action is required as a result of this monitoring event (e.g., action threshold exceeded, ATP test failed, microbial test failed). True = corrective action triggered; False = no action required.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this monitoring record was first created in the system. Supports audit trail requirements under FSMA, GFSI, and SOX financial reporting controls.',
    `economic_threshold` DECIMAL(18,2) COMMENT 'The pest population density level at which economic damage begins to occur, expressed as count per unit area or trap. Used as the baseline for IPM action threshold comparison and treatment justification.',
    `event_date` DATE COMMENT 'Calendar date on which the pest scouting, sanitation, or hygiene verification event was performed. Used for scheduling compliance, PHI (Pre-Harvest Interval) tracking, and FSMA recordkeeping.',
    `event_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the monitoring activity was completed. Used to calculate actual contact time for sanitation agents and total scouting duration.',
    `event_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the monitoring activity commenced. Required for contact time calculations in sanitation events and for audit trail completeness under FSMA preventive controls.',
    `gap_compliance_status` STRING COMMENT 'Assessment of whether this monitoring event meets GAP compliance requirements for field sanitation, pest management, and worker hygiene. Used as evidence in GLOBALG.A.P. and USDA GAP audits.. Valid values are `compliant|non_compliant|not_applicable|pending_review`',
    `gis_coordinates` STRING COMMENT 'Latitude and longitude coordinates (decimal degrees, WGS84) of the monitoring location, captured via GPS for precision agriculture field mapping and spatial analysis in Esri ArcGIS.. Valid values are `^-?d{1,3}.d+,-?d{1,3}.d+$`',
    `gmp_compliance_status` STRING COMMENT 'Assessment of whether this monitoring event meets GMP compliance requirements for sanitation preventive controls in processing and storage facilities. Used as evidence in FDA, SQF, BRC, and IFS audits.. Valid values are `compliant|non_compliant|not_applicable|pending_review`',
    `location_description` STRING COMMENT 'Free-text description of the exact monitoring location within the facility or field, such as North wall corner near loading dock or Field block 4A row 12. Supplements the location code for audit clarity.',
    `microbial_pass_fail` STRING COMMENT 'Pass/fail determination for the microbial test result based on regulatory or facility-defined acceptance criteria. Drives corrective action, product hold, and regulatory notification workflows.. Valid values are `pass|fail|not_tested|pending`',
    `microbial_test_organism` STRING COMMENT 'Specific pathogen or indicator organism targeted by the microbial test (e.g., Listeria monocytogenes, Salmonella, E. coli O157:H7, Total Aerobic Count). Required for FSMA environmental monitoring program documentation.',
    `microbial_test_result` STRING COMMENT 'Result of microbiological testing performed on environmental swabs or surface samples (e.g., Total Plate Count, Listeria spp., Salmonella spp., E. coli). Expressed as colony-forming units per area or detected/not detected. Null if no microbial test was performed.',
    `monitoring_location_code` STRING COMMENT 'Alphanumeric code identifying the specific monitoring point within the facility or field (e.g., trap station ID, zone code, room designation). Aligns with the facilitys IPM monitoring map and GIS field mapping.',
    `monitoring_status` STRING COMMENT 'Current lifecycle state of the monitoring record, from scheduling through completion and quality supervisor sign-off.. Valid values are `scheduled|in_progress|completed|cancelled|pending_review`',
    `monitoring_type` STRING COMMENT 'Discriminator indicating the category of monitoring event: pest scouting (Integrated Pest Management field or facility observation), sanitation execution, hygiene verification, or environmental swab program. Drives which subset of fields is populated.. Valid values are `pest_scouting|sanitation|hygiene_verification|environmental_swab`',
    `notes` STRING COMMENT 'Free-text field for additional observations, anomalies, environmental conditions, or contextual information recorded by the scout or sanitation operator during the monitoring event.',
    `pest_category` STRING COMMENT 'Broad classification of the pest type observed. Supports IPM program reporting, EPA regulatory submissions, and trend analysis across monitoring locations. [ENUM-REF-CANDIDATE: insect|rodent|weed|fungal|bacterial|nematode|bird|other — promote to reference product]',
    `pest_species` STRING COMMENT 'Scientific or common name of the pest species identified during scouting (e.g., Helicoverpa armigera, aphid, rodent). Null for sanitation-type monitoring records. Used for IPM decision-making and EPA pesticide use justification.',
    `population_count` STRING COMMENT 'Number of individual pests observed or captured at the monitoring location during the scouting event. Used to compare against economic threshold and action threshold values for IPM decision-making.',
    `rinse_verification_passed` BOOLEAN COMMENT 'Indicates whether the post-sanitation rinse verification check was passed, confirming removal of cleaning agent residues from food-contact surfaces. True = passed; False = failed, requiring re-sanitation.',
    `sanitation_event_type` STRING COMMENT 'Classification of the sanitation activity performed: pre-operational (before production), operational (during production), post-harvest (after harvest), allergen changeover (between allergen-containing runs), or environmental (scheduled environmental monitoring). Null for pest scouting records.. Valid values are `pre_operational|operational|post_harvest|allergen_changeover|environmental`',
    `sap_qm_notification_number` STRING COMMENT 'SAP S/4HANA QM module notification number associated with this monitoring record, enabling traceability back to the source system of record for quality events and corrective actions.',
    `supervisor_signoff_timestamp` TIMESTAMP COMMENT 'Date and time when the quality supervisor reviewed and approved the monitoring record. Required for FSMA preventive controls documentation and GFSI audit evidence.',
    `trap_placement_date` DATE COMMENT 'Date the trap or monitoring device was placed at the monitoring location. Used to calculate trap exposure duration and assess catch rate per day.',
    `trap_type` STRING COMMENT 'Type of monitoring device or scouting method used to detect or capture pests. Null for sanitation records. [ENUM-REF-CANDIDATE: sticky_trap|pheromone_trap|light_trap|pitfall_trap|bait_station|visual_count|sweep_net — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this monitoring record was last modified. Supports data lineage tracking and audit trail completeness in the Databricks Silver Layer.',
    CONSTRAINT pk_facility_monitoring PRIMARY KEY(`facility_monitoring_id`)
) COMMENT 'Unified facility monitoring records covering IPM pest scouting, sanitation execution, and hygiene verification for fields, storage facilities, processing areas, and equipment. For pest monitoring: captures monitoring location, pest species, population count, trap type and placement, scouting date, economic threshold comparison, action threshold status, and scout identity. For sanitation: captures sanitation event type (pre-operational, operational, post-harvest, allergen changeover), cleaning agent and concentration, contact time, rinse verification, ATP swab or microbial test result, responsible operator, and quality supervisor sign-off. Supports GAP compliance, GMP compliance, EPA pesticide use justification, FSMA sanitation preventive controls, and GFSI audit evidence.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`supplier_assessment` (
    `supplier_assessment_id` BIGINT COMMENT 'Unique system-generated identifier for each supplier assessment record. Primary key for the supplier_assessment data product in the quality domain.',
    `compliance_audit_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_audit. Business justification: Supplier assessments conducted under FSVP (Foreign Supplier Verification Program) or supply chain control programs are formally registered as compliance audits. Linking enables compliance officers to ',
    `cooperator_id` BIGINT COMMENT 'Foreign key linking to research.cooperator. Business justification: Cooperator qualification assessment is a named QA process: before authorizing external farm cooperators for research trials, quality teams assess their GAP compliance, facility standards, and food saf',
    `corrective_action_id` BIGINT COMMENT 'Foreign key linking to quality.corrective_action. Business justification: supplier_assessment has corrective_action_required (BOOLEAN) and corrective_action_due_date (DATE) indicating a CAPA was mandated. Adding corrective_action_id FK links the assessment directly to the C',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: Grower/supplier qualification assessments in produce supply chains evaluate the farm operations land management practices, organic status, and water rights. Linking supplier_assessment to farm_unit e',
    `food_safety_plan_id` BIGINT COMMENT 'Foreign key linking to compliance.food_safety_plan. Business justification: Supplier assessments are supply chain program controls required under FSMA Preventive Controls food safety plans. Linking supplier_assessment to food_safety_plan enables FSMA supply chain control docu',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: Supplier assessments in agriculture are conducted for specific commodities/materials (seed varieties, pesticides, fertilizers). Material-level supplier qualification is a standard procurement quality ',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: A supplier assessment that identifies quality failures should be linked to the resulting nonconformance record. supplier_assessment tracks major_nonconformance_count and minor_nonconformance_count as ',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: Supplier assessments track organic_certified as a boolean flag but must verify against the actual product organic certificate for FSVP compliance and organic supply chain integrity. Linking to organic',
    `previous_assessment_supplier_assessment_id` BIGINT COMMENT 'Reference to the immediately preceding supplier assessment record for the same supplier, enabling longitudinal performance tracking and trend analysis across assessment cycles.',
    `employee_id` BIGINT COMMENT 'Reference to the internal employee or qualified auditor responsible for conducting and signing off on the supplier assessment. Links to the workforce/employee master record.',
    `quality_certification_id` BIGINT COMMENT 'Foreign key linking to quality.quality_certification. Business justification: Supplier assessments evaluate whether suppliers hold required quality certifications (GFSI, GAP, organic, etc.). This FK enables linking assessments to the specific certification being verified. Remov',
    `supplier_sustainability_id` BIGINT COMMENT 'Foreign key linking to sustainability.supplier_sustainability. Business justification: Integrated supplier management programs (EcoVadis, SEDEX, FSVP) combine quality and sustainability scoring for the same vendor. Linking supplier_assessment to supplier_sustainability enables holistic ',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to sustainability.sustainability_certification. Business justification: Supplier approval processes require verification of sustainability certifications (ISCC, Rainforest Alliance, organic). Normalizing organic_certified and gfsi_certification_standard into a FK to susta',
    `vendor_audit_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_audit. Business justification: Supplier quality assessments in agriculture are directly informed by vendor audit results. Linking supplier_assessment to the vendor_audit record enables consolidated supplier approval decisions, GFSI',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Supplier assessments validate compliance with contracted quality requirements (GlobalG.A.P., organic certification, MRL standards specified in the contract). Linking assessment to the active vendor co',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier or vendor being assessed. Links to the master supplier/vendor record in the procurement domain.',
    `approval_date` DATE COMMENT 'Date on which the assessment outcome and supplier approval status were formally approved by the authorized quality manager. Marks the effective start of the approval status for procurement gate purposes.',
    `approval_status` STRING COMMENT 'Procurement quality gate decision resulting from the assessment: approved (supplier meets all quality and compliance requirements), conditional (supplier approved with specific corrective actions required), disqualified (supplier fails minimum standards and is removed from approved vendor list), pending (assessment outcome under review), suspended (supplier temporarily blocked pending investigation).. Valid values are `approved|conditional|disqualified|pending|suspended`',
    `assessment_date` DATE COMMENT 'The actual date on which the supplier assessment was conducted or the primary evaluation activity took place. Used for scheduling, compliance tracking, and reassessment interval calculations.',
    `assessment_due_date` DATE COMMENT 'Scheduled deadline by which the assessment must be completed. Used for compliance monitoring and procurement quality gate enforcement.',
    `assessment_method` STRING COMMENT 'The approach used to conduct the supplier assessment: on_site_audit (physical facility visit), remote_desk_review (off-site document evaluation), questionnaire (self-assessment form), document_review (COA and records review), product_testing (laboratory analysis of supplied inputs), combined (multiple methods applied).. Valid values are `on_site_audit|remote_desk_review|questionnaire|document_review|product_testing|combined`',
    `assessment_number` STRING COMMENT 'Externally-visible business identifier for the assessment record, used in correspondence, audit trails, and regulatory submissions. Format: SA-YYYY-NNNNNN.. Valid values are `^SA-[0-9]{4}-[0-9]{6}$`',
    `assessment_report_number` STRING COMMENT 'Reference number of the formal assessment report document issued upon completion. Used for document management, regulatory submission, and audit trail purposes.',
    `assessment_status` STRING COMMENT 'Current lifecycle state of the assessment record: draft (initiated but not submitted), in_progress (actively being conducted), completed (assessment finalized with outcome), cancelled (assessment voided), pending_review (awaiting quality manager sign-off).. Valid values are `draft|in_progress|completed|cancelled|pending_review`',
    `assessment_type` STRING COMMENT 'Classification of the assessment purpose: pre_qualification (initial onboarding evaluation), periodic_review (scheduled recurring review), for_cause (triggered by non-conformance or complaint), fsvp_verification (FSMA Foreign Supplier Verification Program supply chain verification), re_qualification (re-evaluation after disqualification or lapse).. Valid values are `pre_qualification|periodic_review|for_cause|fsvp_verification|re_qualification`',
    `assessor_organization` STRING COMMENT 'Name of the organization conducting the assessment — may be internal quality team, a third-party certification body (e.g., NSF, SGS, Bureau Veritas), or a regulatory agency. Distinguishes first-party, second-party, and third-party assessments.',
    `corrective_action_due_date` DATE COMMENT 'Deadline by which the supplier must submit evidence of corrective action completion for identified non-conformances. Null when corrective_action_required is False.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether the assessment outcome requires the supplier to submit and implement a corrective action plan (CAP). True when major or critical non-conformances are identified or when conditional approval is granted.',
    `country_of_origin` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the country where the suppliers primary production or manufacturing facility is located. Drives FSVP applicability, COOL (Country of Origin Labeling) compliance, and import risk classification.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the supplier assessment record was first created in the system. Supports audit trail, data lineage, and FSMA record-keeping requirements.',
    `fsvp_verified` BOOLEAN COMMENT 'Indicates whether the supplier has been verified under the FSMA Foreign Supplier Verification Program (FSVP) requirements. Applicable to foreign suppliers of food for human or animal consumption imported into the United States.',
    `gap_certified` BOOLEAN COMMENT 'Indicates whether the supplier holds a current GAP (Good Agricultural Practices) certification such as USDA GAP/GHP or GLOBALG.A.P. at the time of assessment. Relevant for contract growers and fresh produce suppliers.',
    `gmo_status` STRING COMMENT 'Declared GMO status of the primary inputs supplied by this supplier as verified during assessment. Relevant for seed suppliers, feed ingredient suppliers, and crop input vendors. Supports GMO traceability and labeling compliance.. Valid values are `gmo|non_gmo|not_applicable|unknown`',
    `hazard_analysis_conducted` BOOLEAN COMMENT 'Indicates whether a formal HACCP-based hazard analysis was conducted as part of this supplier assessment to identify biological, chemical, and physical hazards associated with the supplied inputs.',
    `major_nonconformance_count` STRING COMMENT 'Number of major non-conformances identified during the assessment. Major non-conformances represent critical failures that directly impact food safety, regulatory compliance, or product quality and require immediate corrective action.',
    `minor_nonconformance_count` STRING COMMENT 'Number of minor non-conformances identified during the assessment. Minor non-conformances represent partial failures or improvement opportunities that do not immediately compromise food safety but require corrective action within a defined timeframe.',
    `notes` STRING COMMENT 'Free-text field for assessor observations, contextual remarks, special conditions, or supplementary findings not captured in structured scoring fields. Supports qualitative documentation for audit readiness.',
    `overall_score` DECIMAL(18,2) COMMENT 'Composite weighted score (0.00–100.00) summarizing the suppliers performance across all evaluated criteria. Calculated from individual criterion scores per the assessment scoring methodology. Drives approval status determination.',
    `reassessment_due_date` DATE COMMENT 'Date by which the next periodic or follow-up supplier assessment must be completed. Drives automated reassessment scheduling and procurement hold triggers when overdue.',
    `report_issued_date` DATE COMMENT 'Date on which the formal supplier assessment report was issued and communicated to relevant stakeholders including procurement, quality management, and the supplier.',
    `risk_level` STRING COMMENT 'Risk classification assigned to the supplier based on assessment findings, product hazard profile, regulatory history, and geographic risk factors. Drives reassessment frequency and procurement control intensity: critical/high require more frequent verification.. Valid values are `critical|high|medium|low`',
    `score_coa_consistency` DECIMAL(18,2) COMMENT 'Criterion score (0.00–100.00) evaluating the consistency, accuracy, and completeness of COA documents provided by the supplier across multiple lots and shipments. Measures alignment between declared and tested values.',
    `score_documentation_completeness` DECIMAL(18,2) COMMENT 'Criterion score (0.00–100.00) evaluating the completeness and accuracy of supplier-submitted documentation including COA records, SDS sheets, regulatory certificates, and quality management system documentation.',
    `score_facility_standards` DECIMAL(18,2) COMMENT 'Criterion score (0.00–100.00) evaluating the suppliers facility conditions including GMP compliance, sanitation, pest control, infrastructure, and food safety environment as observed during on-site or remote assessment.',
    `score_product_conformance` DECIMAL(18,2) COMMENT 'Criterion score (0.00–100.00) evaluating the suppliers historical product conformance based on COA consistency, MRL compliance, lot rejection rates, and non-conformance incident history.',
    `score_regulatory_compliance` DECIMAL(18,2) COMMENT 'Criterion score (0.00–100.00) evaluating the suppliers compliance with applicable regulatory requirements including USDA, FDA, EPA, APHIS registrations, certifications, and inspection records.',
    `supplier_category` STRING COMMENT 'Classification of the type of supplier being assessed, reflecting the nature of inputs or services provided. Drives applicable assessment criteria and regulatory requirements. [ENUM-REF-CANDIDATE: seed_supplier|agrochemical_vendor|feed_ingredient_supplier|contract_grower|packaging_material_provider|fertilizer_supplier|equipment_parts_supplier — promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to the supplier assessment record. Supports change tracking, data lineage, and compliance audit trail requirements.',
    CONSTRAINT pk_supplier_assessment PRIMARY KEY(`supplier_assessment_id`)
) COMMENT 'Supplier and input quality assessment records evaluating quality performance of seed suppliers, agrochemical vendors, feed ingredient suppliers, contract growers, and packaging material providers. Captures supplier identity reference, assessment type (pre-qualification, periodic review, for-cause, FSMA supply chain verification), assessment criteria scores (documentation completeness, facility standards, product conformance history, regulatory compliance, COA consistency), overall rating, approved/conditional/disqualified status, and reassessment due date. Supports procurement quality gate decisions, FSMA Foreign Supplier Verification Program (FSVP), and supply chain preventive controls.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`hold_record` (
    `hold_record_id` BIGINT COMMENT 'Unique system-generated identifier for the product or lot hold record. Primary key for the hold_record data product in the quality domain.',
    `agrochemical_product_id` BIGINT COMMENT 'Foreign key linking to product.agrochemical_product. Business justification: Hold records for MRL exceedances store mrl_active_ingredient as denormalized text. Linking to agrochemical_product enables traceability to the EPA-registered pesticide, supports recall class determina',
    `alert_id` BIGINT COMMENT 'Foreign key linking to weather.weather_alert. Business justification: Quality holds triggered by weather events (hail damage, flood contamination, freeze injury) must reference the causative weather alert for insurance claim documentation and FSMA reportable event evide',
    `case_id` BIGINT COMMENT 'Reference to the customer complaint record that triggered this hold, if the hold originated from a customer-reported quality or food safety issue.',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: Product holds can be placed based on COA results showing MRL exceedances, contamination, or other quality failures. This FK enables tracing holds back to the COA that triggered them. No columns to rem',
    `commodity_id` BIGINT COMMENT 'FK to product.commodity',
    `commodity_lot_id` BIGINT COMMENT 'Reference to the specific commodity lot (LOT/GRN) placed under hold. Enables traceability from hold record back to the inventory lot for FSMA recall readiness.',
    `corrective_action_id` BIGINT COMMENT 'Foreign key linking to quality.corrective_action. Business justification: hold_record has corrective_action_required (BOOLEAN) and corrective_action_due_date (DATE) as denormalized CAPA tracking fields. Adding corrective_action_id FK links the hold directly to the CAPA reco',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Product holds create financial exposure (storage, disposal, demurrage costs) charged to cost centers. The hold_cost_estimate field confirms financial materiality; cost center assignment is required fo',
    `employee_id` BIGINT COMMENT 'Reference to the responsible quality manager or quality assurance personnel who initiated and owns this hold record.',
    `facility_id` BIGINT COMMENT 'Reference to the facility (warehouse, processing plant, or storage location) where the held product or lot is physically located at the time of hold initiation.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: When an MRL exceedance or contamination event is traced to a specific field, all commodity lots from that field may be placed on hold. Linking hold_record to field enables proactive field-level hold m',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Hold-triggered inventory write-downs and disposal costs are posted to GL accounts. The hold_cost_estimate field requires a GL account target for financial posting during period close. Agriculture doma',
    `inspection_finding_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_finding. Business justification: A product hold is frequently initiated as a direct result of an inspection finding (e.g., MRL exceedance finding, food safety risk finding). hold_record has mrl_exceedance_flag, recall_potential, and ',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Product holds can be placed based on failed lab sample results before COA is issued. This FK enables linking holds to the specific sample that triggered the hold decision. No columns to remove as hold',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: Hold records store mrl_threshold_value as a denormalized numeric. Linking to mrl_threshold normalizes the regulatory tolerance that triggered the hold, enabling jurisdiction-specific disposition decis',
    `nonconformance_id` BIGINT COMMENT 'Reference to the nonconformance record that triggered this hold, if applicable. Links to the quality nonconformance tracking entity for root cause traceability.',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Holds on lots affected by precipitation events (hail damage, flood contamination) require direct reference to the precipitation event for USDA disaster reporting and crop insurance indemnity claims. D',
    `procurement_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to procurement.procurement_goods_receipt. Business justification: Holds on incoming agricultural inputs are placed against specific GRNs. hold_record.grn_number is a denormalized text reference; replacing with a proper FK to procurement_goods_receipt enables automat',
    `recall_event_id` BIGINT COMMENT 'Foreign key linking to compliance.recall_event. Business justification: A product hold often precedes or directly triggers a recall event. Quality managers place holds on suspect lots; compliance manages the formal recall. Linking hold_record to recall_event enables trace',
    `test_result_id` BIGINT COMMENT 'Foreign key linking to quality.test_result. Business justification: Product holds can be triggered by specific test result failures (e.g., single MRL exceedance). This FK enables linking holds to the exact test result that failed. Removing mrl_detected_value as this i',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Holds on vendor-supplied materials require direct vendor identification for supplier notification (hold_record.supplier_notified flag exists), SCAR issuance, return claim initiation, and vendor scorec',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this hold record was first created in the system. Used for audit trail, data lineage, and regulatory documentation of when the hold was formally recorded.',
    `disposition` STRING COMMENT 'Final disposition decision for the held lot. release — lot approved for normal use; rework — lot requires reprocessing before use; destroy — lot condemned and destroyed; return_to_supplier — lot returned to originating supplier; downgrade — lot approved for lower-grade use; pending — disposition not yet determined.. Valid values are `release|rework|destroy|return_to_supplier|downgrade|pending`',
    `disposition_date` DATE COMMENT 'The date on which the final disposition decision was made and recorded. Used for regulatory reporting timelines and FSMA recall readiness documentation.',
    `disposition_justification` STRING COMMENT 'Narrative explanation supporting the final disposition decision, including reference to test results, regulatory guidance, or management approval. Required for FSMA and GFSI audit documentation.',
    `fsma_reportable` BOOLEAN COMMENT 'Indicates whether this hold record is subject to FSMA mandatory reporting requirements (e.g., under the Preventive Controls for Human Food rule or the Produce Safety Rule). True triggers regulatory notification workflow.',
    `haccp_ccp_reference` STRING COMMENT 'Identifier of the HACCP Critical Control Point (CCP) whose critical limit was breached, triggering this hold. Null if the hold was not initiated by a HACCP CCP deviation.',
    `hold_cost_estimate` DECIMAL(18,2) COMMENT 'Estimated financial impact of the hold in USD, including potential product loss, rework costs, and operational disruption. Used for financial reporting, COGS impact assessment, and management decision-making.',
    `hold_duration_hours` DECIMAL(18,2) COMMENT 'Total elapsed time in hours from hold initiation to release or current timestamp if still open. Stored as a business field to support SLA monitoring and regulatory reporting without requiring real-time calculation.',
    `hold_initiated_timestamp` TIMESTAMP COMMENT 'The exact date and time the hold was formally initiated and the lot was placed under restriction. This is the principal business event timestamp for the hold record lifecycle.',
    `hold_location_code` STRING COMMENT 'Specific location identifier (bin number, warehouse zone, field block ID, or processing line code) where the held material is physically segregated. Used for warehouse management and physical audit trail.',
    `hold_location_type` STRING COMMENT 'Classification of the physical location type where the held material is stored or segregated. Supports warehouse management integration and physical segregation compliance.. Valid values are `bin|warehouse|field|processing_line|cold_storage|quarantine_area`',
    `hold_number` STRING COMMENT 'Externally-known, human-readable business identifier for the hold record. Used in communications with operations, warehouse, and regulatory bodies. Format: HLD-YYYY-NNNNNN.. Valid values are `^HLD-[0-9]{4}-[0-9]{6}$`',
    `hold_reason` STRING COMMENT 'Detailed narrative description of the specific reason the hold was initiated, including reference to the triggering event (e.g., failed MRL test result, HACCP critical limit breach, customer complaint description, GAP audit finding).',
    `hold_release_timestamp` TIMESTAMP COMMENT 'The date and time the hold was formally released and the lot was returned to unrestricted status. Null if the hold is still active. Used to calculate hold duration and measure quality response time KPIs.',
    `hold_status` STRING COMMENT 'Current lifecycle status of the hold record. open indicates the hold is active and the lot is restricted; released indicates the hold has been lifted; closed indicates final disposition is complete; escalated indicates the hold has been elevated to regulatory or senior management; pending_disposition indicates awaiting final decision.. Valid values are `open|released|closed|escalated|pending_disposition`',
    `hold_type` STRING COMMENT 'Classification of the hold by its primary reason category. quality covers internal quality failures; regulatory covers compliance-driven holds; food_safety covers HACCP or FSMA-triggered holds; mrl_exceedance covers Maximum Residue Limit (MRL) failures; customer_complaint covers holds initiated by customer-reported issues; supplier_deviation covers holds from incoming material nonconformances. [ENUM-REF-CANDIDATE: quality|regulatory|food_safety|mrl_exceedance|customer_complaint|supplier_deviation — promote to reference product]. Valid values are `quality|regulatory|food_safety|mrl_exceedance|customer_complaint|supplier_deviation`',
    `lot_number` STRING COMMENT 'The batch tracking identifier (LOT) of the agricultural commodity, processed product, or input material placed under hold. Used for traceability across the supply chain per FSMA requirements.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, investigation updates, or communication records related to the hold. Supports ongoing investigation documentation and audit trail.',
    `quantity_held` DECIMAL(18,2) COMMENT 'The total quantity of the commodity or product placed under hold, expressed in the unit of measure specified in quantity_uom. Critical for disposition planning and financial impact assessment.',
    `quantity_uom` STRING COMMENT 'Unit of measure for the quantity held. Uses standard agricultural units: BU (Bushel), MT (Metric Ton), CWT (Hundredweight), LB (Pound), KG (Kilogram), TON (Short Ton), GAL (Gallon), L (Liter), BAG, CASE. [ENUM-REF-CANDIDATE: BU|MT|CWT|LB|KG|TON|GAL|L|BAG|CASE — 10 candidates stripped; promote to reference product]',
    `recall_potential` BOOLEAN COMMENT 'Indicates whether this hold has been assessed as having potential to escalate to a product recall. True triggers recall readiness protocols and senior management notification per FSMA and FDA recall procedures.',
    `regulatory_body_notified` STRING COMMENT 'The regulatory authority that was notified of this hold, if regulatory_notification_required is True. Values: USDA, FDA, EPA, FSIS, APHIS, STATE (state-level authority), NONE. [ENUM-REF-CANDIDATE: USDA|FDA|EPA|FSIS|APHIS|STATE|NONE — 7 candidates stripped; promote to reference product]',
    `regulatory_notification_required` BOOLEAN COMMENT 'Indicates whether a regulatory authority (USDA, FDA, EPA, FSIS, or APHIS) must be formally notified of this hold. Drives regulatory reporting workflow and compliance documentation.',
    `sap_usage_decision_code` STRING COMMENT 'The SAP QM module usage decision code recorded in SAP S/4HANA at the time of disposition (e.g., A1 — Accepted, R1 — Rejected, R2 — Rework). Enables direct integration and reconciliation with the ERP system of record.',
    `supplier_notification_date` DATE COMMENT 'Date on which the supplier was formally notified of the hold. Null if supplier_notified is False. Used for supplier quality management and contractual compliance tracking.',
    `supplier_notified` BOOLEAN COMMENT 'Indicates whether the originating supplier has been formally notified of the hold. Required for return-to-supplier disposition and supplier quality management processes.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this hold record was last modified. Used for change tracking, audit trail, and data freshness monitoring in the Databricks Silver Layer.',
    CONSTRAINT pk_hold_record PRIMARY KEY(`hold_record_id`)
) COMMENT 'Product and lot hold records placing agricultural commodities, processed products, or inputs under quality hold pending investigation or disposition. Captures hold type (quality, regulatory, food safety, MRL, customer complaint), affected lot (LOT/GRN), commodity, quantity held, hold initiation reason with source reference (nonconformance ID, test result ID, customer complaint), hold location (bin, warehouse, field, processing line), responsible quality manager, hold start and release dates, duration tracking, and final disposition (release, rework, destroy, return to supplier, downgrade). Integrates with SAP QM usage decision and warehouse management. Critical for FSMA recall readiness and food safety incident response.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`regulatory_submission` (
    `regulatory_submission_id` BIGINT COMMENT 'Unique system-generated identifier for each regulatory submission record. Primary key for the regulatory_submission data product.',
    `alert_id` BIGINT COMMENT 'Foreign key linking to weather.weather_alert. Business justification: FSMA reportable food safety incidents and USDA regulatory submissions triggered by weather events (flooding causing contamination, storm damage) must reference the causative weather alert as supportin',
    `biotech_submission_id` BIGINT COMMENT 'Foreign key linking to research.biotech_submission. Business justification: MRL tolerance petitions and pesticide regulatory submissions in quality are directly supported by biotech/research data packages. Linking quality.regulatory_submission to research.biotech_submission e',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Regulatory submissions (FSMA, USDA, EPA MRL exceedance reports) reference specific commodity lots involved in food safety incidents. Direct lot FK is needed for submissions that are lot-specific (expo',
    `corrective_action_id` BIGINT COMMENT 'Foreign key linking to quality.corrective_action. Business justification: Regulatory submissions often include or reference corrective action plans as required by regulatory agencies (e.g., FDA 483 responses, USDA corrective action plans). Adding corrective_action_id FK lin',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Regulatory submissions (FSMA, pesticide reporting) incur compliance costs (legal fees, filing fees, consultant costs) charged to cost centers. Regulatory compliance cost tracking and SOX control repor',
    `employee_id` BIGINT COMMENT 'Reference to the internal employee or authorized representative responsible for preparing and submitting this regulatory filing to the governing body.',
    `environmental_incident_id` BIGINT COMMENT 'Foreign key linking to sustainability.environmental_incident. Business justification: EPA, state agency, and FSMA regulatory submissions are directly triggered by environmental incidents (pesticide spills, water contamination). This link enables traceability from incident to regulatory',
    `facility_id` BIGINT COMMENT 'Reference to the facility or establishment from which this regulatory submission originates, such as a processing plant, farm operation, or distribution center subject to the filing obligation.',
    `farm_unit_id` BIGINT COMMENT 'Foreign key linking to land.farm_unit. Business justification: USDA organic operation reports, FSMA farm compliance submissions, and state pesticide use reports are submitted at the farm operation level. Linking regulatory_submission to farm_unit enables tracking',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Regulatory penalties and compliance costs from submissions are posted to GL accounts. The estimated_penalty_amount field confirms financial materiality; GL account assignment is required for regulator',
    `hold_record_id` BIGINT COMMENT 'Foreign key linking to quality.hold_record. Business justification: Regulatory submissions may be required for held products, particularly when holds involve food safety incidents, recall potential, or FSMA reportable events. This FK enables linking submissions to the',
    `inspection_finding_id` BIGINT COMMENT 'Foreign key linking to quality.inspection_finding. Business justification: Regulatory submissions can be triggered by serious inspection findings requiring notification to USDA, FDA, or FSIS. This FK enables tracking which findings resulted in regulatory notifications. No co',
    `inspection_id` BIGINT COMMENT 'Reference to the quality inspection record that triggered or is associated with this regulatory submission (e.g., a GAP audit finding that requires an APHIS notification, or a HACCP CCP failure requiring FDA Reportable Food Registry entry).',
    `mrl_threshold_id` BIGINT COMMENT 'Foreign key linking to product.mrl_threshold. Business justification: Regulatory submissions for MRL exceedance reports, tolerance petitions, and EPA/USDA notifications must reference the specific regulatory threshold. Linking regulatory_submission to mrl_threshold enab',
    `nonconformance_id` BIGINT COMMENT 'Reference to the non-conformance record that necessitated this regulatory submission, such as a food safety deviation, MRL (Maximum Residue Limit) exceedance, or critical control point failure requiring mandatory regulatory notification.',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_obligation. Business justification: A quality regulatory submission (FSMA incident report, MRL exceedance notification) fulfills a specific compliance obligation. Linking enables compliance managers to automatically mark obligations as ',
    `parent_submission_regulatory_submission_id` BIGINT COMMENT 'Self-referencing identifier linking this submission to a prior submission it amends, supersedes, or is a resubmission of. Enables tracking of submission amendment chains and version history.',
    `quality_audit_id` BIGINT COMMENT 'Foreign key linking to quality.audit. Business justification: regulatory_submission currently references inspection_id and nonconformance_id but has no link to audit records. Regulatory submissions are frequently triggered by audit findings (e.g., GLOBALG.A.P. a',
    `quality_certification_id` BIGINT COMMENT 'Foreign key linking to quality.quality_certification. Business justification: Regulatory submissions frequently reference or support quality certifications (e.g., USDA Organic certification submissions, GLOBALG.A.P. registration filings, GFSI scheme notifications to regulatory ',
    `regulatory_agency_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_agency. Business justification: quality.regulatory_submission has a plain-text regulatory_agency column that is a denormalized agency name. Normalizing to compliance.regulatory_agency enables agency-level reporting, contact manageme',
    `water_right_id` BIGINT COMMENT 'Foreign key linking to land.water_right. Business justification: Water rights require annual use reports submitted to state agencies (water_right.annual_use_report_required). Linking regulatory_submission to water_right enables tracking of which water right permit ',
    `agency_confirmation_number` STRING COMMENT 'The unique confirmation or tracking number issued by the regulatory agency upon receipt of the submission (e.g., FDA Prior Notice Confirmation Number, USDA permit number). Distinct from the internal submission_number.',
    `agency_response_code` STRING COMMENT 'Standardized code representing the regulatory agencys official determination or response to this submission. Distinct from submission_status which reflects internal workflow state.. Valid values are `approved|denied|additional_info_required|acknowledged|no_action_required`',
    `agency_response_notes` STRING COMMENT 'Free-text notes or summary of the regulatory agencys official response, determination letter, or feedback received. Captures key findings, conditions of approval, or required corrective actions mandated by the agency.',
    `assigned_to` STRING COMMENT 'Name or identifier of the internal compliance officer, regulatory affairs specialist, or team responsible for managing this submission through its lifecycle. Supports workflow assignment and accountability tracking.',
    `certification_standard` STRING COMMENT 'The food safety or agricultural certification standard associated with this submission, where applicable (e.g., SQF - Safe Quality Food, BRC - British Retail Consortium, IFS - International Featured Standards, GLOBALG.A.P. - Global Good Agricultural Practices, USDA NOP for organic). Supports GFSI certification readiness tracking.. Valid values are `SQF|BRC|IFS|GLOBALG.A.P.|ISO_22000|NOP|HACCP|FSMA`',
    `commodity_description` STRING COMMENT 'Description of the agricultural commodity, product, or food category that is the subject of this regulatory submission (e.g., fresh produce, processed grain, livestock, pesticide product). Supports COOL (Country of Origin Labeling) and traceability reporting.',
    `compliance_deadline` DATE COMMENT 'The regulatory-mandated or internally-set deadline by which this submission must be filed or a response must be provided to remain in compliance. Used for SOP-driven deadline monitoring and KPI reporting.',
    `confidential_flag` BOOLEAN COMMENT 'Indicates whether this submission contains confidential business information (CBI) as designated under applicable regulatory frameworks (e.g., EPA CBI claims under FIFRA, FDA trade secret designations). True if CBI protections apply.',
    `country_of_origin` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code indicating the country of origin of the commodity or product covered by this submission. Required for COOL (Country of Origin Labeling) compliance and export health certificate filings.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this regulatory submission record was first created in the system. Supports audit trail requirements and data lineage tracking in the Databricks Silver Layer.',
    `estimated_penalty_amount` DECIMAL(18,2) COMMENT 'Estimated monetary penalty or fine exposure associated with this regulatory submission in the event of non-compliance or rejection. Expressed in USD. Used for financial risk assessment and CAPEX/OPEX planning.',
    `external_counsel_ref` STRING COMMENT 'Reference to external legal counsel or regulatory consultant engaged to support this submission, where applicable. Captures the firm name or engagement reference for attorney-client privilege tracking.',
    `fsma_rule_category` STRING COMMENT 'Specific FSMA (Food Safety Modernization Act) rule category applicable to this submission. Enables granular FSMA compliance tracking across the seven major rules. Null if submission is not FSMA-related.. Valid values are `produce_safety|preventive_controls_human|preventive_controls_animal|foreign_supplier_verification|sanitary_transport|intentional_adulteration`',
    `penalty_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the estimated_penalty_amount (e.g., USD for US Dollar). Supports multi-currency financial risk reporting for international operations.. Valid values are `^[A-Z]{3}$`',
    `priority_level` STRING COMMENT 'Internal priority classification assigned to this submission based on regulatory risk, deadline urgency, and potential business impact. Supports KPI-driven compliance management and resource allocation.. Valid values are `critical|high|medium|low`',
    `regulatory_program_code` STRING COMMENT 'Specific regulatory program or rule under which this submission is filed (e.g., FSMA Produce Safety Rule, FSMA Preventive Controls, USDA NOP, EPA FIFRA Section 6(a)(2), GLOBALG.A.P.). Enables grouping and reporting by compliance program.',
    `response_received_date` DATE COMMENT 'The date on which the official response, acknowledgment, or determination was received from the regulatory agency following the submission. Null if no response has been received yet.',
    `resubmission_due_date` DATE COMMENT 'The deadline by which a corrected or amended submission must be filed with the regulatory agency following a rejection or request for additional information. Null if resubmission_required is False.',
    `resubmission_required` BOOLEAN COMMENT 'Indicates whether the regulatory agency has required a resubmission or amendment to this filing due to deficiencies, missing information, or rejection. True if resubmission is required; False otherwise.',
    `submission_date` DATE COMMENT 'The calendar date on which the regulatory submission was officially filed or transmitted to the regulatory agency. This is the principal business event date for the submission lifecycle.',
    `submission_description` STRING COMMENT 'Detailed narrative description of the regulatory submission, including the scope, purpose, and any relevant context about the filing obligation, the triggering event, or the regulatory requirement being fulfilled.',
    `submission_method` STRING COMMENT 'The channel or mechanism used to transmit the regulatory submission to the agency (e.g., electronic via FDA ESG portal, paper mail, agency web portal, fax). Supports audit trail and process improvement analysis.. Valid values are `electronic|paper|portal|mail|fax`',
    `submission_number` STRING COMMENT 'Externally-known unique reference number assigned to this submission, either by the submitting organization or by the receiving regulatory agency upon acknowledgment. Used for tracking and correspondence (e.g., FDA registration number, USDA permit number).',
    `submission_period_end` DATE COMMENT 'The end date of the reporting or compliance period covered by this submission. Together with submission_period_start, defines the temporal scope of the regulatory report.',
    `submission_period_start` DATE COMMENT 'The start date of the reporting or compliance period covered by this submission (e.g., start of the annual pesticide use reporting period, beginning of the organic certification cycle). Applicable for periodic filings.',
    `submission_status` STRING COMMENT 'Current lifecycle state of the regulatory submission as tracked by the quality and compliance team. Reflects the last known status from the regulatory agency or internal workflow.. Valid values are `pending|accepted|rejected|under_review|withdrawn`',
    `submission_title` STRING COMMENT 'Descriptive title or name of the regulatory submission as used in official correspondence and internal tracking (e.g., Annual Pesticide Use Report FY2024, FSMA Facility Registration Renewal, Organic Certification Application - North Farm).',
    `submission_type` STRING COMMENT 'Classification of the regulatory submission by its purpose and program. [ENUM-REF-CANDIDATE: fsma_facility_registration|reportable_food_registry|pesticide_use_report|organic_certification_application|export_health_certificate|prior_notice|adverse_event_report|label_approval|import_permit|environmental_compliance_report — promote to reference product]',
    `supporting_document_ref` STRING COMMENT 'Reference identifier or path to the supporting documentation package associated with this submission, such as COA (Certificate of Analysis), SDS (Safety Data Sheet), laboratory test results, or audit reports stored in the document management system.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this regulatory submission record was last modified. Tracks the most recent update to submission status, agency response, or any other field for audit and compliance purposes.',
    CONSTRAINT pk_regulatory_submission PRIMARY KEY(`regulatory_submission_id`)
) COMMENT 'Records of regulatory submissions, notifications, and filings made to governing bodies including USDA, FDA, FSIS, EPA, and APHIS. Captures submission type (FSMA facility registration, Reportable Food Registry entry, pesticide use report, organic certification application, export health certificate), regulatory agency, submission date, submission reference number, submission status (pending, accepted, rejected, under review), response received date, and compliance deadline. SSOT for regulatory reporting obligations in the quality and food safety domain.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`environmental_monitoring` (
    `environmental_monitoring_id` BIGINT COMMENT 'Unique surrogate identifier for each environmental monitoring record in the food safety surveillance program.',
    `corrective_action_id` BIGINT COMMENT 'Foreign key linking to quality.corrective_action. Business justification: environmental_monitoring has corrective_action_triggered (BOOLEAN) indicating a CAPA was initiated. Adding corrective_action_id FK replaces this boolean with a direct reference to the specific correct',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Environmental monitoring programs (water testing, pathogen surveillance under FSMA) incur lab and sampling costs charged to cost centers. Regulatory compliance cost tracking and cost-of-quality report',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Environmental monitoring (water testing, soil sampling, pathogen swabbing) in agriculture is executed by specific field or lab crews. Crew-level attribution is required for FSMA environmental monitori',
    `employee_id` BIGINT COMMENT 'Reference to the responsible quality manager who owns the monitoring zone and oversees corrective action response for this sample site.',
    `environmental_incident_id` BIGINT COMMENT 'Foreign key linking to sustainability.environmental_incident. Business justification: Positive E. coli results in irrigation water monitoring or pathogen detections in environmental monitoring directly trigger environmental incident reports under FSMA Produce Safety Rule and GAP standa',
    `facility_id` BIGINT COMMENT 'Reference to the processing facility, storage area, or agricultural site where the environmental monitoring sample was collected.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: FSMA Produce Safety Rule (21 CFR Part 112) requires agricultural water testing tied to specific growing fields. Linking environmental_monitoring to field enables field-level water quality compliance r',
    `food_safety_plan_id` BIGINT COMMENT 'Foreign key linking to compliance.food_safety_plan. Business justification: Environmental monitoring (Listeria, E. coli, generic E. coli) is a mandatory verification activity under FSMA Preventive Controls food safety plans. Linking monitoring records to the food safety plan ',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: Environmental monitoring (pathogen surveillance) is a critical component of HACCP programs, particularly for FSMA preventive controls. This FK links monitoring records to the HACCP plan they support. ',
    `irrigation_zone_id` BIGINT COMMENT 'Foreign key linking to land.irrigation_zone. Business justification: FSMA PSR requires agricultural water testing at the point of application, which corresponds to specific irrigation zones. Linking environmental_monitoring to irrigation_zone enables zone-level water q',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Environmental monitoring events generate lab samples for pathogen and indicator organism testing (e.g., Listeria spp., generic E. coli). Adding lab_sample_id FK links the environmental monitoring even',
    `laboratory_id` BIGINT COMMENT 'Reference to the internal or external laboratory that performed the microbiological analysis on the environmental sample.',
    `nonconformance_id` BIGINT COMMENT 'Reference to the nonconformance record created when this environmental monitoring result triggered a corrective action. Links to the quality.nonconformance product for full corrective action lifecycle tracking.',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: FSMA Produce Safety Rule requires agricultural water quality monitoring to account for weather conditions at time of sampling. Linking environmental_monitoring to the concurrent weather observation su',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Environmental monitoring programs (water quality, discharge, pathogen) are conducted under the terms of environmental permits (NPDES, CAFO, water withdrawal). Linking monitoring records to the governi',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: FSMA Produce Safety Rule explicitly requires post-precipitation water quality sampling. Linking environmental_monitoring to the triggering precipitation event is a direct regulatory compliance require',
    `regulatory_submission_id` BIGINT COMMENT 'Foreign key linking to quality.regulatory_submission. Business justification: environmental_monitoring has regulatory_submission_required (BOOLEAN) and fsma_program_code indicating regulatory reporting obligations. Adding regulatory_submission_id FK links the monitoring record ',
    `sample_site_id` BIGINT COMMENT 'Unique identifier for the physical sampling location within the facility or field (e.g., floor drain, conveyor belt, water source inlet). Used for trend analysis and site-specific corrective action tracking.',
    `storage_location_id` BIGINT COMMENT 'Foreign key linking to inventory.storage_location. Business justification: Environmental monitoring (Listeria, E. coli, water testing) is conducted at specific storage locations within a facility. FSMA Preventive Controls and GAP compliance require traceability of environmen',
    `trial_id` BIGINT COMMENT 'Foreign key linking to research.trial. Business justification: Trial site environmental monitoring (pathogen, water quality) is a named FSMA and GAP compliance process: environmental monitoring events at active trial sites must be linked to the trial for trial s',
    `water_right_id` BIGINT COMMENT 'Foreign key linking to land.water_right. Business justification: FSMA PSR agricultural water testing must be conducted on the actual permitted water source. Linking environmental_monitoring to water_right enables tracking of which permitted water source was tested ',
    `water_stewardship_plan_id` BIGINT COMMENT 'Foreign key linking to sustainability.water_stewardship_plan. Business justification: Water stewardship plans require documented water quality monitoring as evidence of plan implementation. Linking environmental_monitoring records to the water_stewardship_plan they support enables plan',
    `parent_environmental_monitoring_id` BIGINT COMMENT 'Self-referencing FK on environmental_monitoring (parent_environmental_monitoring_id)',
    `action_limit` DECIMAL(18,2) COMMENT 'Threshold value at or above which a corrective action is automatically triggered. For pathogens, any detection constitutes an action limit breach. For indicator organisms, this is the numeric threshold defined in the environmental monitoring program.',
    `collected_by` STRING COMMENT 'Name or employee identifier of the individual who physically collected the environmental sample. Required for chain-of-custody documentation and FSMA audit evidence.',
    `collection_method` STRING COMMENT 'Physical method used to collect the environmental sample. Sponge and swab methods are standard for surface sampling; water grab is used for agricultural water sources per FSMA Produce Safety Rule requirements.. Valid values are `Sponge|Swab|Water Grab|Rinse|Contact Plate|Air Sample`',
    `collection_timestamp` TIMESTAMP COMMENT 'Date and time when the environmental sample was physically collected from the monitoring site. Principal business event timestamp for this record. Used for trend analysis, frequency compliance verification, and FSMA audit trails.',
    `confirmatory_test_required` BOOLEAN COMMENT 'Indicates whether a confirmatory (second) test is required following a presumptive positive result. True when initial screening detects a pathogen and confirmation by an alternative validated method is mandated by the monitoring program or regulatory requirement.',
    `consecutive_positive_count` STRING COMMENT 'Number of consecutive positive or above-threshold results recorded at this sample site prior to and including the current result. Used to evaluate adverse trends and escalate corrective action intensity per the environmental monitoring program.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this environmental monitoring record was first created in the system. Supports audit trail requirements and data lineage tracking in the Databricks Lakehouse silver layer.',
    `fsma_program_code` STRING COMMENT 'FSMA regulatory program under which this environmental monitoring event is conducted: PC-HF = Preventive Controls for Human Food (21 CFR Part 117); PC-AF = Preventive Controls for Animal Food (21 CFR Part 507); PSR = Produce Safety Rule (21 CFR Part 112); FSVP = Foreign Supplier Verification Program.. Valid values are `PC-HF|PC-AF|PSR|FSVP`',
    `gap_audit_evidence_flag` BOOLEAN COMMENT 'Indicates whether this environmental monitoring record is designated as audit evidence for a GAP or GLOBALG.A.P. certification audit. Flagged records are included in audit evidence packages and must meet documentation completeness requirements.',
    `generic_e_coli_result` DECIMAL(18,2) COMMENT 'Numeric generic E. coli count in MPN/100mL for agricultural water samples. FSMA Produce Safety Rule specifies a geometric mean threshold of 126 MPN/100mL and a statistical threshold value (STV) of 410 MPN/100mL for agricultural water used on produce.',
    `gfsi_scheme` STRING COMMENT 'The GFSI-benchmarked certification scheme under which this environmental monitoring record serves as audit evidence. Determines specific documentation and frequency requirements applicable to this record.. Valid values are `SQF|BRC|IFS|FSSC 22000|GLOBALG.A.P.`',
    `laboratory_accreditation_number` STRING COMMENT 'ISO/IEC 17025 accreditation number of the laboratory that performed the analysis. Required for GFSI audit evidence and FSMA regulatory submissions to demonstrate use of validated, accredited testing methods.',
    `monitoring_program_version` STRING COMMENT 'Version identifier of the written environmental monitoring program document under which this sample was collected. Ensures results are evaluated against the correct action limits and frequencies as the program evolves over time.',
    `monitoring_record_number` STRING COMMENT 'Externally-visible business identifier for the environmental monitoring event, used in GFSI audit evidence packages and FSMA regulatory submissions. Format: EM-YYYY-NNNNNN.. Valid values are `^EM-[0-9]{4}-[0-9]{6}$`',
    `monitoring_zone` STRING COMMENT 'Zone classification of the sample site per industry-standard environmental monitoring zoning: Zone 1 = direct food contact surfaces; Zone 2 = adjacent non-food contact surfaces; Zone 3 = areas removed from food contact; Zone 4 = external/remote areas. Drives sampling frequency and corrective action thresholds.. Valid values are `Zone 1|Zone 2|Zone 3|Zone 4`',
    `notes` STRING COMMENT 'Free-text field for additional observations, anomalies, or contextual information recorded at the time of sample collection or result review (e.g., equipment downtime, unusual environmental conditions, sanitizer change).',
    `pass_fail_status` STRING COMMENT 'Overall pass or fail determination for this environmental monitoring sample based on comparison of the test result against the action limit and program specifications. Drives corrective action workflow initiation.. Valid values are `Pass|Fail|Pending|Inconclusive`',
    `qualitative_result` STRING COMMENT 'Qualitative outcome of the environmental microbiological test. For pathogen testing (Listeria, Salmonella), results are typically reported as Detected/Not Detected. Presumptive Positive triggers confirmatory testing before corrective action.. Valid values are `Detected|Not Detected|Presumptive Positive|Inconclusive`',
    `quantitative_result` DECIMAL(18,2) COMMENT 'Numeric count or concentration result for indicator organism testing (e.g., coliform count, aerobic plate count). Expressed in the unit defined by result_unit_of_measure. Null for qualitative-only pathogen tests.',
    `result_reported_timestamp` TIMESTAMP COMMENT 'Date and time the final test result was reported by the laboratory to the quality team. Used to measure turnaround time and ensure timely corrective action initiation within program-defined windows.',
    `result_status` STRING COMMENT 'Workflow status of the test result record. Preliminary results are reported before confirmatory testing; Confirmed indicates a presumptive positive has been verified; Final indicates the result is locked for regulatory and audit purposes.. Valid values are `Preliminary|Confirmed|Final|Voided|Under Review`',
    `result_unit_of_measure` STRING COMMENT 'Unit of measure for the quantitative test result (e.g., CFU/cm2 for surface swabs, CFU/mL for water samples, MPN/100mL for agricultural water per FSMA Produce Safety Rule). Null when result is qualitative only.. Valid values are `CFU/cm2|CFU/mL|CFU/g|MPN/100mL|Log CFU/cm2`',
    `sample_received_timestamp` TIMESTAMP COMMENT 'Date and time the environmental sample was received at the laboratory. Used to calculate sample hold time compliance and chain-of-custody integrity.',
    `sample_site_description` STRING COMMENT 'Descriptive name and location detail of the sampling point (e.g., Floor drain near chiller exit, Zone 2, Building A). Supports audit evidence and site mapping.',
    `sampling_frequency` STRING COMMENT 'Scheduled frequency at which this monitoring site is sampled as defined in the environmental monitoring program plan. Used to verify compliance with program requirements and identify gaps in monitoring coverage.. Valid values are `Daily|Weekly|Bi-Weekly|Monthly|Quarterly|Event-Based`',
    `sap_qm_inspection_lot` STRING COMMENT 'SAP S/4HANA QM module inspection lot number associated with this environmental monitoring event. Enables traceability between the lakehouse silver layer record and the originating SAP QM inspection lot for audit and reconciliation purposes.',
    `target_organism` STRING COMMENT 'The pathogen or indicator organism being tested in this monitoring event. Drives test method selection, action limits, and regulatory notification requirements. [ENUM-REF-CANDIDATE: Listeria spp.|Listeria monocytogenes|Salmonella|E. coli O157:H7|Generic E. coli|Coliforms|Aerobic Plate Count|Yeast and Mold — promote to reference product]. Valid values are `Listeria spp.|Listeria monocytogenes|Salmonella|E. coli O157:H7|Generic E. coli|Coliforms|Aerobic Plate Count|Yeast and Mold`',
    `test_method_code` STRING COMMENT 'Standardized analytical method code used for pathogen or indicator organism detection (e.g., AOAC 2004.02 for Listeria, BAM Chapter 5 for Salmonella, ISO 11290-1 for Listeria monocytogenes). Ensures method traceability for GFSI and regulatory audits.',
    `trend_analysis_flag` BOOLEAN COMMENT 'Indicates whether this result has been flagged by the trend analysis algorithm as part of an adverse trend pattern (e.g., repeated indicator organism positives in the same zone, increasing counts over consecutive sampling events). Triggers proactive investigation before action limit is breached.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this environmental monitoring record was last modified. Supports change tracking, audit trail requirements, and incremental data pipeline processing in the Databricks Lakehouse silver layer.',
    `water_source_type` STRING COMMENT 'Classification of the water source when the monitoring site is an agricultural water source. Required for FSMA Produce Safety Rule compliance. Null for non-water monitoring sites.. Valid values are `Agricultural Water|Municipal Water|Well Water|Surface Water|Recycled Water`',
    CONSTRAINT pk_environmental_monitoring PRIMARY KEY(`environmental_monitoring_id`)
) COMMENT 'Environmental monitoring program records for pathogen and indicator organism surveillance in processing facilities, storage areas, and agricultural water sources. Captures monitoring zone classification (Zone 1-4), sample site identifier, target organism (Listeria spp., Salmonella, E. coli, coliforms), sampling frequency, collection method (sponge, swab, water grab), test result, trend analysis flag, corrective action trigger status, and responsible quality manager. Supports FSMA Preventive Controls environmental monitoring requirements, GFSI audit evidence, and proactive contamination prevention programs critical to food safety in agriculture.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`laboratory` (
    `laboratory_id` BIGINT COMMENT 'Primary key for laboratory',
    `parent_laboratory_id` BIGINT COMMENT 'Self-referencing FK on laboratory (parent_laboratory_id)',
    `accreditation_body` STRING COMMENT 'Name of the accreditation body that granted laboratory certification (e.g., A2LA, ANAB, UKAS).',
    `accreditation_effective_date` DATE COMMENT 'Date when the laboratory accreditation became effective.',
    `accreditation_expiration_date` DATE COMMENT 'Date when the current laboratory accreditation expires and requires renewal.',
    `accreditation_number` STRING COMMENT 'Unique accreditation certificate number issued by the accreditation body.',
    `accreditation_status` STRING COMMENT 'Current accreditation status of the laboratory under ISO/IEC 17025 or equivalent standards.',
    `address_line_1` STRING COMMENT 'Primary street address of the laboratory facility.',
    `address_line_2` STRING COMMENT 'Secondary address information such as suite, building, or floor number.',
    `biosafety_level` STRING COMMENT 'Biosafety level classification for laboratories handling biological agents.',
    `city` STRING COMMENT 'City where the laboratory is located.',
    `clia_certificate_number` STRING COMMENT 'CLIA certificate number if laboratory performs clinical testing on agricultural workers or food safety personnel.',
    `country_code` STRING COMMENT 'Three-letter ISO country code where the laboratory is located.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this laboratory record was first created in the system.',
    `data_integrity_compliance` BOOLEAN COMMENT 'Indicates whether the laboratory meets data integrity requirements under ALCOA+ principles (Attributable, Legible, Contemporaneous, Original, Accurate, Complete, Consistent, Enduring, Available).',
    `equipment_calibration_frequency_days` STRING COMMENT 'Standard frequency in days for calibration of laboratory testing equipment.',
    `established_date` DATE COMMENT 'Date when the laboratory was established and began operations.',
    `fda_registration_number` STRING COMMENT 'FDA registration number for laboratories conducting food safety testing under FSMA requirements.',
    `gfsi_certification_scheme` STRING COMMENT 'GFSI-recognized certification scheme the laboratory operates under (e.g., SQF, BRC, IFS, FSSC 22000). [ENUM-REF-CANDIDATE: SQF|BRC|IFS|FSSC_22000|GLOBALG.A.P.|PrimusGFS|CanadaGAP — promote to reference product]',
    `laboratory_code` STRING COMMENT 'Externally-known unique code for the laboratory used in regulatory filings and certifications.',
    `laboratory_name` STRING COMMENT 'Official registered name of the laboratory facility.',
    `laboratory_type` STRING COMMENT 'Classification of laboratory based on operational model and ownership structure.',
    `last_audit_date` DATE COMMENT 'Date of the most recent external audit or assessment of the laboratory.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this laboratory record was last updated.',
    `lims_system_name` STRING COMMENT 'Name of the Laboratory Information Management System used for sample tracking and data management.',
    `next_audit_scheduled_date` DATE COMMENT 'Scheduled date for the next external audit or surveillance assessment.',
    `operational_status` STRING COMMENT 'Current operational status of the laboratory facility.',
    `postal_code` STRING COMMENT 'Postal or ZIP code for the laboratory location.',
    `primary_contact_email` STRING COMMENT 'Email address of the primary laboratory contact for quality and compliance communications.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary contact person or laboratory director.',
    `primary_contact_phone` STRING COMMENT 'Primary phone number for the laboratory contact.',
    `proficiency_testing_participation` BOOLEAN COMMENT 'Indicates whether the laboratory participates in proficiency testing programs to validate testing competency.',
    `quality_management_system` STRING COMMENT 'Quality management system framework the laboratory operates under.',
    `specialization_area` STRING COMMENT 'Primary area of laboratory specialization (e.g., microbiology, chemistry, pesticide residue, mycotoxin, allergen, GMO, nutritional analysis).',
    `state_province` STRING COMMENT 'State or province where the laboratory is located.',
    `testing_capacity_samples_per_day` STRING COMMENT 'Maximum number of samples the laboratory can process per day under normal operating conditions.',
    `testing_scope` STRING COMMENT 'Comprehensive description of testing capabilities and scope of accreditation including test methods and matrices.',
    `turnaround_time_standard_hours` STRING COMMENT 'Standard turnaround time in hours for routine test results from sample receipt to report delivery.',
    `usda_establishment_number` STRING COMMENT 'USDA establishment number for laboratories testing meat, poultry, and egg products.',
    CONSTRAINT pk_laboratory PRIMARY KEY(`laboratory_id`)
) COMMENT 'Master reference table for laboratory. Referenced by laboratory_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`sample_site` (
    `sample_site_id` BIGINT COMMENT 'Primary key for sample_site',
    `facility_id` BIGINT COMMENT 'Reference to the parent facility or production location where this sample site is physically located.',
    `haccp_plan_id` BIGINT COMMENT 'Reference to the HACCP plan governing critical control point monitoring at this sample site.',
    `test_panel_id` BIGINT COMMENT 'Reference to the standard testing protocol or inspection program applied to samples collected from this site.',
    `parent_sample_site_id` BIGINT COMMENT 'Self-referencing FK on sample_site (parent_sample_site_id)',
    `address_line_1` STRING COMMENT 'Primary street address line for the sample site location. Required for USDA, FDA, and FSIS regulatory reporting and audit traceability.',
    `address_line_2` STRING COMMENT 'Secondary address line for the sample site (building, suite, or unit information).',
    `certification_expiry_date` DATE COMMENT 'Date when the current food safety certification for this sample site expires and requires renewal.',
    `certification_scheme` STRING COMMENT 'Name of the food safety certification scheme applicable to this sample site (e.g., SQF, BRC, IFS, GLOBALG.A.P., FSSC 22000). [ENUM-REF-CANDIDATE: SQF|BRC|IFS|GLOBALG.A.P.|FSSC_22000|HACCP|Organic|Fair_Trade — promote to reference product]',
    `certification_status` STRING COMMENT 'Current certification status of the sample site for GFSI schemes (SQF, BRC, IFS) and GLOBALG.A.P. audit readiness.',
    `city` STRING COMMENT 'City or municipality where the sample site is located.',
    `contact_email` STRING COMMENT 'Primary email address for the sample site contact person for quality coordination and audit communication.',
    `contact_person_name` STRING COMMENT 'Full name of the primary contact person responsible for quality sampling and coordination at this site.',
    `contact_phone` STRING COMMENT 'Primary phone number for the sample site contact person for urgent quality or compliance matters.',
    `country_code` STRING COMMENT 'Three-letter ISO country code identifying the country where the sample site is located.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this sample site record was first created in the quality management system.',
    `effective_end_date` DATE COMMENT 'Date when this sample site was decommissioned or ceased quality sampling operations. Null for currently active sites.',
    `effective_start_date` DATE COMMENT 'Date when this sample site became active and operational for quality sampling activities.',
    `establishment_number` STRING COMMENT 'Official establishment number assigned by regulatory authority (e.g., USDA FSIS establishment number) for regulatory reporting and traceability.',
    `fsma_compliant` BOOLEAN COMMENT 'Indicates whether this sample site meets FSMA compliance requirements for preventive controls and food safety plans.',
    `gap_gmp_compliant` BOOLEAN COMMENT 'Indicates whether this sample site is currently compliant with GAP and GMP standards as verified by audit findings.',
    `last_audit_date` DATE COMMENT 'Date of the most recent quality or food safety audit conducted at this sample site.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this sample site record was last updated or modified in the quality management system.',
    `latitude` DECIMAL(18,2) COMMENT 'Geographic latitude coordinate of the sample site location in decimal degrees for precision mapping and traceability.',
    `longitude` DECIMAL(18,2) COMMENT 'Geographic longitude coordinate of the sample site location in decimal degrees for precision mapping and traceability.',
    `mrl_testing_required` BOOLEAN COMMENT 'Indicates whether Maximum Residue Limit testing for pesticides and contaminants is required for samples from this site.',
    `next_audit_date` DATE COMMENT 'Scheduled date for the next quality or food safety audit at this sample site.',
    `notes` STRING COMMENT 'Additional notes, comments, or special instructions related to sampling procedures, site-specific requirements, or audit observations for this sample site.',
    `operational_hours` STRING COMMENT 'Standard operational hours or shift schedule for the sample site indicating when sampling activities can be conducted.',
    `postal_code` STRING COMMENT 'Postal or ZIP code for the sample site address.',
    `regulatory_authority` STRING COMMENT 'Primary regulatory body with jurisdiction over this sample site (e.g., USDA, FDA, FSIS, state agriculture department). [ENUM-REF-CANDIDATE: USDA|FDA|FSIS|EPA|State_Ag_Dept|EU_Commission|CFIA|FSANZ — promote to reference product]',
    `sampling_frequency` STRING COMMENT 'Standard frequency at which quality samples are collected from this site according to the quality assurance testing protocol.',
    `sap_plant_code` STRING COMMENT 'SAP S/4HANA plant code corresponding to this sample site for integration with SAP Quality Management (QM) module.',
    `site_code` STRING COMMENT 'Externally-known unique business identifier code for the sample site used in quality documentation, Certificate of Analysis (COA) records, and regulatory reporting.',
    `site_name` STRING COMMENT 'Human-readable name of the sample site location or facility where quality samples are collected.',
    `site_status` STRING COMMENT 'Current operational status of the sample site in the quality management system lifecycle.',
    `site_type` STRING COMMENT 'Classification of the sample site indicating the type of location where samples are collected for quality assurance testing.',
    `state_province` STRING COMMENT 'State, province, or regional administrative division where the sample site is located.',
    CONSTRAINT pk_sample_site PRIMARY KEY(`sample_site_id`)
) COMMENT 'Master reference table for sample_site. Referenced by sample_site_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`inspection_lot` (
    `inspection_lot_id` BIGINT COMMENT 'Primary key for inspection_lot',
    `approved_by_employee_id` BIGINT COMMENT 'Reference to the quality manager or authorized personnel who approved the inspection lot for release.',
    `batch_id` BIGINT COMMENT 'Reference to the production batch associated with this inspection lot for traceability.',
    `employee_id` BIGINT COMMENT 'Reference to the quality inspector or auditor responsible for conducting the inspection.',
    `facility_id` BIGINT COMMENT 'Reference to the facility or plant where the inspection is being conducted.',
    `plan_id` BIGINT COMMENT 'Reference to the inspection plan or protocol that defines the testing procedures and acceptance criteria for this lot.',
    `material_master_id` BIGINT COMMENT 'Reference to the material or product being inspected in this lot.',
    `production_order_id` BIGINT COMMENT 'Reference to the production order that generated this inspection lot, applicable for finished goods and work-in-process.',
    `vendor_id` BIGINT COMMENT 'Reference to the supplier who provided the material being inspected, applicable for raw material and ingredient lots.',
    `parent_inspection_lot_id` BIGINT COMMENT 'Self-referencing FK on inspection_lot (parent_inspection_lot_id)',
    `acceptance_quality_limit` DECIMAL(18,2) COMMENT 'Maximum percentage of defects or non-conformances acceptable for the lot to be approved, expressed as a percentage.',
    `approval_timestamp` TIMESTAMP COMMENT 'Date and time when the inspection lot was officially approved by authorized quality personnel.',
    `certificate_issue_date` DATE COMMENT 'Date when the Certificate of Analysis was officially issued for this inspection lot.',
    `certificate_of_analysis_number` STRING COMMENT 'Unique identifier for the Certificate of Analysis document generated for this inspection lot.',
    `corrective_action_required_flag` BOOLEAN COMMENT 'Indicates whether corrective actions are required based on the inspection findings.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this inspection lot record was first created in the system.',
    `critical_defect_count` STRING COMMENT 'Number of critical defects identified that pose safety risks or render the product unusable.',
    `defect_count` STRING COMMENT 'Total number of defects or non-conformances identified during the inspection.',
    `expiration_date` DATE COMMENT 'Date after which the inspected lot is no longer considered acceptable for use or sale, applicable for perishable goods.',
    `inspection_completion_timestamp` TIMESTAMP COMMENT 'Date and time when all inspection activities for this lot were completed.',
    `inspection_notes` STRING COMMENT 'Free-text field for inspectors to record observations, findings, or additional context about the inspection lot.',
    `inspection_severity` STRING COMMENT 'Severity level of the inspection based on historical quality performance and risk assessment.',
    `inspection_start_timestamp` TIMESTAMP COMMENT 'Date and time when the inspection activities for this lot commenced.',
    `inspection_status` STRING COMMENT 'Current lifecycle status of the inspection lot within the quality assurance workflow.',
    `inspection_type` STRING COMMENT 'Classification of the inspection based on when it occurs in the production or supply chain process.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when this inspection lot record was last updated.',
    `lot_number` STRING COMMENT 'Business identifier for the inspection lot, externally visible and used in quality documentation and Certificate of Analysis (COA) records.',
    `lot_size_quantity` DECIMAL(18,2) COMMENT 'Total quantity of material or product in this inspection lot.',
    `lot_size_unit` STRING COMMENT 'Unit of measure for the lot size quantity.',
    `lot_type` STRING COMMENT 'Classification of the inspection lot based on the material or product category being inspected.',
    `major_defect_count` STRING COMMENT 'Number of major defects identified that significantly impact product functionality or quality.',
    `minor_defect_count` STRING COMMENT 'Number of minor defects identified that have minimal impact on product quality or functionality.',
    `quarantine_flag` BOOLEAN COMMENT 'Indicates whether the inspection lot is currently under quarantine and restricted from use or shipment.',
    `quarantine_reason` STRING COMMENT 'Explanation for why the inspection lot has been placed under quarantine, including specific quality or safety concerns.',
    `release_date` DATE COMMENT 'Date when the inspection lot was officially released for use, sale, or further processing following approval.',
    `sample_size_quantity` DECIMAL(18,2) COMMENT 'Quantity of material drawn from the lot for inspection and testing purposes.',
    `sample_size_unit` STRING COMMENT 'Unit of measure for the sample size quantity.',
    `sampling_method` STRING COMMENT 'Method used to collect samples from the inspection lot for testing.',
    `usage_decision` STRING COMMENT 'Final disposition decision for the inspected lot determining whether it can be released for use, sale, or further processing.',
    CONSTRAINT pk_inspection_lot PRIMARY KEY(`inspection_lot_id`)
) COMMENT 'Master reference table for inspection_lot. Referenced by inspection_lot_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`test_panel` (
    `test_panel_id` BIGINT COMMENT 'Primary key for test_panel',
    `laboratory_id` BIGINT COMMENT 'Identifier of the primary laboratory or testing facility authorized to execute this test panel.',
    `quality_standard_id` BIGINT COMMENT 'Identifier of the quality standard or specification this test panel is designed to verify compliance against.',
    `parent_test_panel_id` BIGINT COMMENT 'Self-referencing FK on test_panel (parent_test_panel_id)',
    `accreditation_required` BOOLEAN COMMENT 'Indicates whether this test panel requires accredited laboratory execution per regulatory or certification requirements.',
    `accreditation_standard` STRING COMMENT 'The accreditation standard or certification scheme required for this test panel (e.g., ISO/IEC 17025, AOAC, USDA, FDA).',
    `allergen_testing_included` BOOLEAN COMMENT 'Indicates whether this test panel includes allergen detection or quantification tests.',
    `applicable_product_categories` STRING COMMENT 'Comma-separated list of product categories or commodity types for which this test panel is applicable (e.g., fresh produce, dairy, meat, grains).',
    `approval_date` DATE COMMENT 'Date when this test panel was formally approved for operational use.',
    `approved_by` STRING COMMENT 'Name or identifier of the quality manager or technical authority who approved this test panel for operational use.',
    `certification_scheme` STRING COMMENT 'Food safety certification scheme this test panel supports (e.g., SQF, BRC, IFS, GLOBALG.A.P.).',
    `cost_per_panel` DECIMAL(18,2) COMMENT 'Standard cost to execute this test panel including all individual tests, labor, and materials.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this test panel record was first created in the quality management system.',
    `critical_control_point` BOOLEAN COMMENT 'Indicates whether this test panel monitors a critical control point in the HACCP food safety plan.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the cost per panel.',
    `test_panel_description` STRING COMMENT 'Detailed description of the test panel including scope, objectives, and testing methodology overview.',
    `effective_date` DATE COMMENT 'Date when this test panel version became effective and available for use in quality testing programs.',
    `expiration_date` DATE COMMENT 'Date when this test panel version expires or is scheduled for retirement. Null for open-ended panels.',
    `hazard_analysis_required` BOOLEAN COMMENT 'Indicates whether this test panel requires formal hazard analysis and critical control point (HACCP) documentation.',
    `last_review_date` DATE COMMENT 'Date of the most recent review and validation of this test panel.',
    `maximum_residue_limit_applicable` BOOLEAN COMMENT 'Indicates whether this test panel includes maximum residue limit (MRL) testing for pesticides, veterinary drugs, or contaminants.',
    `method_reference` STRING COMMENT 'Reference to the analytical method or standard operating procedure (SOP) document governing this test panel execution.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this test panel record was last modified or updated.',
    `next_review_date` DATE COMMENT 'Scheduled date for the next periodic review and validation of this test panel.',
    `notes` STRING COMMENT 'Additional notes, comments, or special instructions related to the execution or interpretation of this test panel.',
    `panel_category` STRING COMMENT 'Business category indicating the purpose of the test panel (routine quality control, regulatory compliance, certification audit, customer complaint investigation, method validation, or research and development).',
    `panel_code` STRING COMMENT 'Externally-known unique alphanumeric code identifying the test panel in laboratory and quality systems.',
    `panel_name` STRING COMMENT 'Human-readable name of the test panel describing the suite of tests performed.',
    `panel_type` STRING COMMENT 'Classification of the test panel by testing discipline (microbiological, chemical, physical, sensory, nutritional, or allergen testing).',
    `pathogen_testing_included` BOOLEAN COMMENT 'Indicates whether this test panel includes pathogen detection tests (e.g., Salmonella, E. coli, Listeria).',
    `regulatory_framework` STRING COMMENT 'Primary regulatory framework or food safety program this test panel supports (e.g., FSMA, HACCP, GFSI, GLOBALG.A.P.).',
    `review_frequency_months` STRING COMMENT 'Required frequency in months for periodic review and validation of the test panel to ensure continued relevance and accuracy.',
    `sample_size_required` DECIMAL(18,2) COMMENT 'Minimum sample size or quantity required to execute the complete test panel.',
    `sample_unit_of_measure` STRING COMMENT 'Unit of measure for the required sample size (grams, kilograms, milliliters, liters, units, or each).',
    `test_panel_status` STRING COMMENT 'Current lifecycle status of the test panel indicating whether it is available for use in quality testing programs.',
    `test_count` STRING COMMENT 'Total number of individual tests included in this test panel.',
    `turnaround_time_hours` STRING COMMENT 'Standard turnaround time in hours from sample receipt to results reporting for this test panel.',
    `version_number` STRING COMMENT 'Version number of the test panel specification following semantic versioning (major.minor format).',
    CONSTRAINT pk_test_panel PRIMARY KEY(`test_panel_id`)
) COMMENT 'Master reference table for test_panel. Referenced by test_panel_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`batch` (
    `batch_id` BIGINT COMMENT 'Primary key for batch',
    `parent_batch_id` BIGINT COMMENT 'Self-referencing FK on batch (parent_batch_id)',
    `batch_number` STRING COMMENT 'Externally-known unique batch number assigned during production. Used for traceability across supply chain and regulatory reporting.',
    `batch_status` STRING COMMENT 'Current lifecycle status of the batch in the quality management workflow.',
    `batch_type` STRING COMMENT 'Classification of batch purpose: full production run, pilot test, rework of rejected material, or quality sample batch.',
    `best_before_date` DATE COMMENT 'Date until which the product maintains optimal quality characteristics. Distinct from expiration for food safety.',
    `certification_status` STRING COMMENT 'Status of third-party certification for this batch (e.g., organic, non-GMO, fair trade).',
    `coa_issued` BOOLEAN COMMENT 'Indicates whether a Certificate of Analysis has been issued for this batch documenting quality test results.',
    `coa_number` STRING COMMENT 'Unique identifier for the Certificate of Analysis document issued for this batch.',
    `corrective_action_id` BIGINT COMMENT 'Reference to the corrective action record initiated for this batchs non-conformances.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether corrective action is required for non-conformances identified in this batch.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this batch record was first created in the system.',
    `expiration_date` DATE COMMENT 'Date after which the batch is no longer safe or suitable for consumption or use. Calculated based on production date and shelf life.',
    `facility_id` BIGINT COMMENT 'Reference to the production facility where this batch was manufactured.',
    `fsma_compliant` BOOLEAN COMMENT 'Indicates whether the batch meets FDA FSMA preventive controls and traceability requirements.',
    `gfsi_scheme` STRING COMMENT 'GFSI-recognized certification scheme under which this batch was produced (SQF, BRC, IFS, FSSC 22000, GLOBALG.A.P.).',
    `haccp_compliant` BOOLEAN COMMENT 'Indicates whether the batch was produced in compliance with HACCP critical control point requirements.',
    `hold_reason` STRING COMMENT 'Detailed explanation of why the batch is on quality hold, if applicable. Includes non-conformance details.',
    `inspection_date` DATE COMMENT 'Date when the quality inspection was performed on this batch.',
    `inspector_id` BIGINT COMMENT 'Reference to the quality inspector who performed the batch inspection and released or rejected the batch.',
    `lot_code` STRING COMMENT 'Production lot code printed on packaging for consumer traceability and recall management.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this batch record was last modified in the system.',
    `mrl_compliant` BOOLEAN COMMENT 'Indicates whether the batch passed MRL testing and meets regulatory limits for pesticide residues.',
    `mrl_tested` BOOLEAN COMMENT 'Indicates whether the batch was tested for pesticide and chemical residue levels against regulatory MRL limits.',
    `pathogen_result` STRING COMMENT 'Result of pathogen testing: negative (safe), positive (contaminated), pending, or not tested.',
    `pathogen_tested` BOOLEAN COMMENT 'Indicates whether the batch was tested for foodborne pathogens (Salmonella, E. coli, Listeria, etc.).',
    `product_id` BIGINT COMMENT 'Reference to the product master record that this batch represents.',
    `production_date` DATE COMMENT 'Date when the batch production was completed. Critical for shelf-life calculation and traceability.',
    `production_line_id` BIGINT COMMENT 'Reference to the specific production line or equipment used to manufacture this batch.',
    `production_timestamp` TIMESTAMP COMMENT 'Precise timestamp when batch production was completed, including time zone. Used for HACCP critical control point documentation.',
    `quality_grade` STRING COMMENT 'Quality classification assigned to the batch based on inspection results and product specifications.',
    `quantity_produced` DECIMAL(18,2) COMMENT 'Total quantity of product manufactured in this batch, measured in the products base unit of measure.',
    `quantity_rejected` DECIMAL(18,2) COMMENT 'Quantity of the batch that failed quality inspection and was rejected or quarantined.',
    `quantity_released` DECIMAL(18,2) COMMENT 'Quantity of the batch that passed quality inspection and was released for distribution.',
    `recall_date` DATE COMMENT 'Date when a recall was initiated for this batch, if applicable.',
    `recall_status` STRING COMMENT 'Current status of any product recall action associated with this batch.',
    `rejection_reason` STRING COMMENT 'Detailed explanation of why the batch was rejected, including specific quality failures or non-conformances.',
    `release_date` DATE COMMENT 'Date when the batch was officially released for distribution after passing quality inspection.',
    `supplier_id` BIGINT COMMENT 'Reference to the supplier who provided raw materials for this batch, for upstream traceability.',
    `unit_of_measure` STRING COMMENT 'Unit of measure for the quantity produced (kilograms, pounds, liters, etc.).',
    CONSTRAINT pk_batch PRIMARY KEY(`batch_id`)
) COMMENT 'Master reference table for batch. Referenced by batch_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`production_order` (
    `production_order_id` BIGINT COMMENT 'Primary key for production_order',
    `parent_production_order_id` BIGINT COMMENT 'Self-referencing FK on production_order (parent_production_order_id)',
    `actual_end_timestamp` TIMESTAMP COMMENT 'Actual date and time when production was completed for this order.',
    `actual_quantity` DECIMAL(18,2) COMMENT 'Actual quantity of product units successfully manufactured and accepted.',
    `actual_start_timestamp` TIMESTAMP COMMENT 'Actual date and time when production began for this order.',
    `batch_number` STRING COMMENT 'Unique batch or lot number assigned to the production run for traceability and recall management.',
    `coa_issued_date` DATE COMMENT 'Date when the Certificate of Analysis was issued for this production batch.',
    `coa_issued_flag` BOOLEAN COMMENT 'Indicates whether a Certificate of Analysis has been issued for this production batch.',
    `corrective_action_required_flag` BOOLEAN COMMENT 'Indicates whether corrective actions are required to address quality issues in this production order.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this production order record was first created in the system.',
    `facility_id` BIGINT COMMENT 'Reference to the production facility or plant where this order is being executed.',
    `fsma_compliance_flag` BOOLEAN COMMENT 'Indicates whether this production order meets FSMA preventive controls and compliance requirements.',
    `gap_audit_status` STRING COMMENT 'Status of GAP audit compliance for this production order, applicable to farm-level operations.',
    `gfsi_certification_scheme` STRING COMMENT 'Applicable GFSI-recognized food safety certification scheme under which this production order is executed.',
    `gmp_audit_status` STRING COMMENT 'Status of GMP audit compliance for this production order, applicable to processing facilities.',
    `haccp_plan_id` BIGINT COMMENT 'Reference to the HACCP plan governing critical control points for this production order.',
    `modified_by` STRING COMMENT 'User identifier of the person who last modified this production order record.',
    `modified_timestamp` TIMESTAMP COMMENT 'Date and time when this production order record was last modified.',
    `mrl_testing_required_flag` BOOLEAN COMMENT 'Indicates whether pesticide or chemical residue testing is required for this production batch.',
    `mrl_testing_status` STRING COMMENT 'Current status of pesticide and chemical residue testing for this production batch.',
    `non_conformance_count` STRING COMMENT 'Total number of quality non-conformances identified during production of this order.',
    `notes` STRING COMMENT 'Free-text notes and comments related to production execution, quality observations, or special handling instructions.',
    `order_number` STRING COMMENT 'Externally-known business identifier for the production order, used across systems and documentation.',
    `order_status` STRING COMMENT 'Current lifecycle state of the production order in the manufacturing workflow.',
    `order_type` STRING COMMENT 'Classification of the production order based on its purpose and processing requirements.',
    `planned_quantity` DECIMAL(18,2) COMMENT 'Target quantity of product units to be manufactured in this production order.',
    `product_code` STRING COMMENT 'Material or SKU code for the product being manufactured.',
    `product_id` BIGINT COMMENT 'Reference to the finished good or intermediate product being manufactured in this production order.',
    `product_name` STRING COMMENT 'Human-readable name of the product being manufactured.',
    `production_line_id` BIGINT COMMENT 'Reference to the specific production line or work center assigned to this order.',
    `quality_status` STRING COMMENT 'Current quality inspection and approval status of the production batch.',
    `regulatory_agency` STRING COMMENT 'Primary regulatory agency with jurisdiction over this production order.',
    `regulatory_hold_flag` BOOLEAN COMMENT 'Indicates whether this production batch is under regulatory hold pending inspection or approval.',
    `rejected_quantity` DECIMAL(18,2) COMMENT 'Quantity of product units rejected due to quality non-conformance during production.',
    `scheduled_end_date` DATE COMMENT 'Planned date when production is scheduled to be completed for this order.',
    `scheduled_start_date` DATE COMMENT 'Planned date when production is scheduled to begin for this order.',
    `supervisor_id` BIGINT COMMENT 'Reference to the production supervisor responsible for overseeing this production order.',
    `traceability_code` STRING COMMENT 'Unique traceability identifier for supply chain tracking and recall management.',
    `unit_of_measure` STRING COMMENT 'Standard unit of measure for the production quantities.',
    `created_by` STRING COMMENT 'User identifier of the person who created this production order record.',
    CONSTRAINT pk_production_order PRIMARY KEY(`production_order_id`)
) COMMENT 'Master reference table for production_order. Referenced by production_order_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`quality`.`quality_standard` (
    `quality_standard_id` BIGINT COMMENT 'Primary key for quality_standard',
    `parent_quality_standard_id` BIGINT COMMENT 'Self-referencing FK on quality_standard (parent_quality_standard_id)',
    `annual_compliance_cost_usd` DECIMAL(18,2) COMMENT 'Estimated annual cost in USD to maintain compliance with this quality standard, including audit fees, certification fees, testing costs, training expenses, and internal labor. Used for budgeting and cost-benefit analysis of quality programs.',
    `applicable_facility_types` STRING COMMENT 'Comma-separated list of facility or operation types to which this quality standard applies (e.g., farm, packing house, processing plant, cold storage, distribution center, retail). Defines the scope of operations covered.',
    `applicable_product_categories` STRING COMMENT 'Comma-separated list of product categories or commodity groups to which this quality standard applies (e.g., fresh produce, dairy, meat and poultry, processed foods, animal feed, packaging materials). Defines the scope of products covered.',
    `audit_frequency_months` STRING COMMENT 'Required frequency for third-party audits or internal assessments against this quality standard, expressed in months (e.g., 12 for annual, 24 for biennial). Null if no periodic audit is required.',
    `certification_body` STRING COMMENT 'Name of the accredited organization that issues or governs this quality standard (e.g., SQFI, BRC Global Standards, IFS Management GmbH, GLOBALG.A.P. c/o FoodPLUS GmbH, NSF International, SGS, Bureau Veritas). Null for internal or non-certified standards.',
    `certification_duration_months` STRING COMMENT 'Validity period of certification issued under this quality standard, expressed in months (e.g., 12, 24, 36). After this period, recertification audit is required. Null for non-certification standards.',
    `corrective_action_timeframe_days` STRING COMMENT 'Maximum number of days allowed to implement corrective actions for non-conformances identified during audits or assessments under this quality standard. Timeframe varies by severity of finding (e.g., 30 days for major, 90 days for minor).',
    `country_codes` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country codes where this quality standard is applicable or recognized (e.g., USA, CAN, MEX, DEU, GBR, CHN). Null for global standards applicable everywhere.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this quality standard record was first created in the system. Used for audit trail and data lineage tracking.',
    `critical_defect_threshold` STRING COMMENT 'Maximum number of critical non-conformances allowed before automatic failure of audit or assessment. Critical defects are findings that pose immediate food safety risk or regulatory violation. Zero tolerance is common for many food safety standards.',
    `documentation_requirements` STRING COMMENT 'Description of mandatory documentation, records, and evidence that must be maintained to demonstrate compliance with this quality standard (e.g., HACCP plans, SOPs, training records, COA files, corrective action logs, supplier approvals).',
    `effective_date` DATE COMMENT 'Date when this version of the quality standard becomes enforceable or recommended for adoption. Organizations must comply with the standard from this date forward for new certifications or audits.',
    `expiration_date` DATE COMMENT 'Date when this version of the quality standard is superseded or retired. After this date, organizations must transition to the next version. Null for standards with indefinite validity.',
    `geographic_scope` STRING COMMENT 'Geographic applicability of the quality standard. Global standards apply worldwide (ISO, GFSI schemes), regional standards apply to multi-country regions (EU regulations), national standards apply to a single country (USDA, FDA), state standards apply to sub-national jurisdictions, and local standards apply to specific municipalities or districts.',
    `gfsi_recognized_flag` BOOLEAN COMMENT 'Indicates whether this quality standard is benchmarked and recognized by the Global Food Safety Initiative (GFSI). GFSI recognition is a key requirement for many global retailers and food manufacturers. True if GFSI-recognized, false otherwise.',
    `internal_owner_department` STRING COMMENT 'Name of the internal department or business unit responsible for managing compliance with this quality standard (e.g., Quality Assurance, Food Safety, Regulatory Affairs, Operations). Used for accountability and audit coordination.',
    `issuing_authority` STRING COMMENT 'Regulatory or governing body that mandates or oversees the standard (e.g., USDA, FDA, FSIS, European Commission, Codex Alimentarius, state agriculture departments). Applicable for regulatory and industry standards.',
    `last_reviewed_date` DATE COMMENT 'Date when this quality standard was last reviewed by internal quality management team for continued applicability, accuracy, and alignment with business needs. Used to ensure master data currency and trigger periodic reviews.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this quality standard record was most recently modified. Used for audit trail, change tracking, and data freshness monitoring.',
    `major_defect_threshold` STRING COMMENT 'Maximum number of major non-conformances allowed before failure of audit or assessment. Major defects are significant deviations from standard requirements that could lead to food safety issues if not corrected.',
    `minimum_score_required` DECIMAL(18,2) COMMENT 'Minimum audit score or compliance percentage required to achieve certification or pass assessment under this quality standard (e.g., 80.00 for 80% compliance). Null if the standard does not use numeric scoring.',
    `next_review_date` DATE COMMENT 'Scheduled date for the next periodic review of this quality standard record. Used to trigger proactive review workflows and ensure master data remains current with evolving regulatory and industry requirements.',
    `notes` STRING COMMENT 'Free-text field for additional information, special considerations, implementation guidance, or historical context related to this quality standard. Used to capture nuances not covered by structured fields.',
    `reference_document_url` STRING COMMENT 'Web URL link to the official published standard document, guidance materials, or certification body website where the full standard text and requirements can be accessed.',
    `regulatory_mandate_flag` BOOLEAN COMMENT 'Indicates whether compliance with this quality standard is legally required by government regulation (e.g., FSMA Preventive Controls, HACCP for seafood and juice). True if mandated by law, false if voluntary or industry-driven.',
    `scope_description` STRING COMMENT 'Detailed description of what the quality standard covers, including applicable products, processes, facilities, and supply chain stages. Defines the boundaries of compliance requirements and audit scope.',
    `standard_category` STRING COMMENT 'Primary functional category of the quality standard. Food safety covers pathogen control and contamination prevention (HACCP, FSMA), quality management covers systematic quality assurance (ISO 9001, SQF), good agricultural practices cover on-farm production (GLOBALG.A.P.), good manufacturing practices cover processing facility operations (GMP, cGMP), hazard analysis covers risk assessment methodologies (HACCP principles), and traceability covers supply chain tracking (PTI, FSMA 204).',
    `standard_code` STRING COMMENT 'Unique business identifier code for the quality standard (e.g., SQF-2000, BRC-8, IFS-7, HACCP-001, GAP-V5). Used for external reference and certification documentation.',
    `standard_name` STRING COMMENT 'Full official name of the quality standard (e.g., Safe Quality Food Level 2, British Retail Consortium Global Standard for Food Safety, International Featured Standards Food).',
    `standard_type` STRING COMMENT 'Classification of the quality standard by its origin and enforcement mechanism. Certification standards are third-party verified (GFSI schemes), regulatory are government-mandated (FDA, USDA, FSIS), internal are company-defined, industry are sector-wide best practices, customer-specific are buyer requirements, and voluntary are optional compliance frameworks.',
    `quality_standard_status` STRING COMMENT 'Current lifecycle status of the quality standard. Active standards are in force and enforceable, superseded standards have been replaced by newer versions, draft standards are under development, under review standards are being evaluated for adoption, retired standards are no longer applicable, and suspended standards are temporarily not enforced.',
    `supplier_approval_requirements` STRING COMMENT 'Description of supplier qualification, approval, and monitoring requirements mandated by this quality standard (e.g., supplier audits, COA review, risk-based supplier verification, FSMA Foreign Supplier Verification Program requirements).',
    `testing_protocol_requirements` STRING COMMENT 'Description of mandatory testing, sampling, and analytical methods required by this quality standard (e.g., pathogen testing frequency, MRL testing protocols, environmental monitoring programs, finished product testing specifications).',
    `traceability_requirements` STRING COMMENT 'Description of traceability and supply chain tracking requirements mandated by this quality standard (e.g., one-up/one-back traceability, lot coding requirements, recall readiness, FSMA 204 Key Data Elements for high-risk foods).',
    `training_requirements` STRING COMMENT 'Description of mandatory training programs and competency requirements for personnel involved in activities covered by this quality standard (e.g., HACCP training for food safety team, GMP training for production staff, auditor qualification requirements).',
    `version_number` STRING COMMENT 'Version or edition number of the quality standard (e.g., 8.0, 7.1, V5.2). Quality standards are periodically revised to incorporate new science, regulatory changes, and industry best practices.',
    CONSTRAINT pk_quality_standard PRIMARY KEY(`quality_standard_id`)
) COMMENT 'Master reference table for quality_standard. Referenced by quality_standard_id.';

